using UnityEngine;

[CreateAssetMenu(fileName = "NewRangedWeapon", menuName = "Weapons/Ranged Weapon")]
public class RangedWeapon : Weapon
{
    [Header("Ranged")]
    public GameObject projectilePrefab;
    public float projectileSpeed = 20f;

    public override void Use(PlayerController player)
    {
        this.PlayAnimation(player);

        if (this.projectilePrefab == null)
        {
            return;
        }

        GameObject projectile = Object.Instantiate(
            this.projectilePrefab,
            player.firePoint.position,
            player.firePoint.rotation
        );

        RangedProjectile projectileComponent = projectile.GetComponent<RangedProjectile>();

        if (projectileComponent != null)
        {
            projectileComponent.Initialize(player, this);
        }

        Rigidbody projectileRb = projectile.GetComponent<Rigidbody>();

        if (projectileRb != null)
        {
            projectileRb.linearVelocity = player.firePoint.forward * this.projectileSpeed;
        }
    }
}

