using System.Collections.Generic;
using UnityEngine;

[CreateAssetMenu(fileName = "NewMeleeWeapon", menuName = "Weapons/Melee Weapon")]
public class MeleeWeapon : Weapon
{
    [Header("Melee")]
    public float attackRange = 2f;
    public float coneAngle = 90f;
    public float attackHeightOffset = 1f;
    public LayerMask hitMask;

    [Header("Line Of Sight")]
    public bool requireLineOfSight = true;
    public LayerMask lineOfSightMask = ~0;

    public override void Use(PlayerController player)
    {
        this.PlayAnimation(player);

        Vector3 origin = player.transform.position + Vector3.up * this.attackHeightOffset;

        Collider[] colliders = Physics.OverlapSphere(
            origin,
            this.attackRange,
            this.hitMask,
            QueryTriggerInteraction.Collide
        );

        float halfConeAngle = this.coneAngle * 0.5f;
        float cosineThreshold = Mathf.Cos(halfConeAngle * Mathf.Deg2Rad);

        Vector3 forward = player.visuals.forward;
        forward.y = 0f;
        forward.Normalize();

        HashSet<PlayerController> hitPlayers = new HashSet<PlayerController>();

        foreach (Collider collider in colliders)
        {
            PlayerController targetPlayer = collider.GetComponentInParent<PlayerController>();

            if (targetPlayer == null)
            {
                continue;
            }

            if (targetPlayer == player)
            {
                continue;
            }

            if (hitPlayers.Contains(targetPlayer))
            {
                continue;
            }

            Vector3 directionToTarget = targetPlayer.transform.position - player.transform.position;
            directionToTarget.y = 0f;

            if (directionToTarget.sqrMagnitude <= 0.0001f)
            {
                continue;
            }

            directionToTarget.Normalize();

            float dot = Vector3.Dot(forward, directionToTarget);

            if (dot < cosineThreshold)
            {
                continue;
            }

            if (this.requireLineOfSight)
            {
                Vector3 lineOfSightOrigin = origin;
                Vector3 lineOfSightTarget = targetPlayer.transform.position + Vector3.up * this.attackHeightOffset;
                Vector3 lineOfSightDirection = lineOfSightTarget - lineOfSightOrigin;
                float lineOfSightDistance = lineOfSightDirection.magnitude;

                if (lineOfSightDistance > 0.0001f)
                {
                    lineOfSightDirection /= lineOfSightDistance;

                    RaycastHit hit;

                    if (Physics.Raycast(
                        lineOfSightOrigin,
                        lineOfSightDirection,
                        out hit,
                        lineOfSightDistance,
                        this.lineOfSightMask,
                        QueryTriggerInteraction.Collide
                    ))
                    {
                        PlayerController hitPlayer = hit.collider.GetComponentInParent<PlayerController>();

                        if (hitPlayer != targetPlayer)
                        {
                            continue;
                        }
                    }
                }
            }

            hitPlayers.Add(targetPlayer);
            targetPlayer.OnHit(player, this);
        }

        Debug.Log($"Melee attack with {this.weaponName}");
    }
}

