using UnityEngine;

public class RangedProjectile : Projectile
{
    [Header("Environment")]
    public LayerMask environmentMask = ~0;

    protected override void Awake()
    {
        base.Awake();
        this.rb.useGravity = false;
    }

    private void FixedUpdate()
    {
        float distance = this.rb.linearVelocity.magnitude * Time.fixedDeltaTime;

        if (Physics.Raycast(
            this.transform.position,
            this.rb.linearVelocity.normalized,
            distance,
            this.environmentMask,
            QueryTriggerInteraction.Ignore
        ))
        {
            this.DestroyProjectile();
        }
    }
}

