using UnityEngine;
using UnityEngine.InputSystem;

[RequireComponent(typeof(Rigidbody))]
[RequireComponent(typeof(PlayerInput))]
public class PlayerController : MonoBehaviour, IHittable
{
    private const string ANIMATOR_SPEED = "Speed";
    private const string ANIMATOR_IS_MOVING = "IsMoving";

    [Header("Movement")]
    public float moveSpeed = 5f;
    public float visualRotationSpeed = 12f;

    [Header("References")]
    public Animator animator { get; private set; }
    public Rigidbody rb { get; private set; }
    public PlayerInput playerInput { get; private set; }

    [Header("Transforms")]
    [SerializeField] private Transform firePointTransform;
    [SerializeField] private Transform visualsTransform;

    public Transform firePoint
    {
        get
        {
            if (this.firePointTransform != null)
            {
                return this.firePointTransform;
            }

            return transform;
        }
    }

    public Transform visuals
    {
        get
        {
            if (this.visualsTransform != null)
            {
                return this.visualsTransform;
            }

            return transform;
        }
    }

    [Header("State Machine")]
    public StateMachine stateMachine { get; private set; }

    [Header("States")]
    public PlayerIdleState playerIdleState { get; private set; }
    public PlayerMoveState playerMoveState { get; private set; }
    public PlayerMeleeAttackState playerMeleeAttackState { get; private set; }
    public PlayerRangedAttackState playerRangedAttackState { get; private set; }
    public PlayerThrowAttackState playerThrowAttackState { get; private set; }
    public PlayerSpecialAbilityState playerSpecialAbilityState { get; private set; }
    public PlayerDeathState playerDeathState { get; private set; }

    [Header("Weapons")]
    public MeleeWeapon meleeWeapon;
    public RangedWeapon rangedWeapon;
    public ThrowWeapon throwWeapon;

    [Header("Player Data")]
    public PlayerData playerData { get; set; }
    public int playerIndex { get; set; }

    [Header("Inputs")]
    public Vector2 moveInput { get; private set; }
    public bool meleeAttackPressed { get; private set; }
    public bool rangedAttackPressed { get; private set; }
    public bool throwAttackPressed { get; private set; }
    public bool specialAbilityPressed { get; private set; }

    private void Awake()
    {
        this.animator = GetComponent<Animator>();
        this.rb = GetComponent<Rigidbody>();
        this.playerInput = GetComponent<PlayerInput>();

        this.stateMachine = new StateMachine();

        this.playerIdleState = new PlayerIdleState(this);
        this.playerMoveState = new PlayerMoveState(this);
        this.playerMeleeAttackState = new PlayerMeleeAttackState(this);
        this.playerRangedAttackState = new PlayerRangedAttackState(this);
        this.playerThrowAttackState = new PlayerThrowAttackState(this);
        this.playerSpecialAbilityState = new PlayerSpecialAbilityState(this);
        this.playerDeathState = new PlayerDeathState(this);
    }

    private void Start()
    {
        this.stateMachine.ChangeState(this.playerIdleState);
    }

    private bool IsInLobby()
    {
        return GameManager.instance != null && GameManager.instance.currentState == GameState.Lobby;
    }

    private void Update()
    {
        if (this.IsInLobby())
        {
            return;
        }

        this.stateMachine.Update();

        this.ResetInputTriggers();
        this.UpdateAnimatorParameters();
    }

    private void FixedUpdate()
    {
        if (this.IsInLobby())
        {
            return;
        }

        this.stateMachine.FixedUpdate();
    }

    private void ResetInputTriggers()
    {
        this.meleeAttackPressed = false;
        this.rangedAttackPressed = false;
        this.throwAttackPressed = false;
        this.specialAbilityPressed = false;
    }

    private void UpdateAnimatorParameters()
    {
        if (this.animator == null)
        {
            return;
        }

        Vector3 horizontalVelocity = new Vector3(
            this.rb.linearVelocity.x,
            0f,
            this.rb.linearVelocity.z
        );

        this.SetMovementAnimation(
            horizontalVelocity.magnitude,
            horizontalVelocity.magnitude > 0.05f
        );
    }

    public void SetMovementAnimation(float speed, bool isMoving)
    {
        if (this.animator == null)
        {
            return;
        }

        this.animator.SetFloat(ANIMATOR_SPEED, speed);
        this.animator.SetBool(ANIMATOR_IS_MOVING, isMoving);
    }

    public void ResetMovementAnimation()
    {
        this.SetMovementAnimation(0f, false);
    }

    public void PlayAnimationTrigger(string triggerName)
    {
        if (this.animator == null)
        {
            return;
        }

        if (string.IsNullOrEmpty(triggerName))
        {
            return;
        }

        this.animator.SetTrigger(triggerName);
    }

    public void RotateVisualsTowards(Vector3 worldDirection)
    {
        if (worldDirection.sqrMagnitude < 0.0001f)
        {
            return;
        }

        Quaternion targetRotation = Quaternion.LookRotation(worldDirection, Vector3.up);

        this.visuals.rotation = Quaternion.Slerp(
            this.visuals.rotation,
            targetRotation,
            this.visualRotationSpeed * Time.deltaTime
        );
    }

    public void OnMove(InputValue value)
    {
        this.moveInput = value.Get<Vector2>();
    }

    public void OnMeleeAttack(InputValue value)
    {
        if (value.isPressed)
        {
            if (this.IsInLobby())
            {
                GameManager.instance.TogglePlayerReady(this.playerIndex);
                return;
            }

            this.meleeAttackPressed = true;
        }
    }

    public void OnRangedAttack(InputValue value)
    {
        if (this.IsInLobby())
        {
            return;
        }

        if (value.isPressed)
        {
            this.rangedAttackPressed = true;
        }
    }

    public void OnThrowAttack(InputValue value)
    {
        if (this.IsInLobby())
        {
            return;
        }

        if (value.isPressed)
        {
            this.throwAttackPressed = true;
        }
    }

    public void OnSpecialAbility(InputValue value)
    {
        if (this.IsInLobby())
        {
            return;
        }

        if (value.isPressed)
        {
            this.specialAbilityPressed = true;
        }
    }

    public void OnHit(PlayerController attacker, Weapon weapon)
    {
        if (this.stateMachine.currentState == this.playerDeathState)
        {
            return;
        }

        if (GameManager.instance != null)
        {
            GameManager.instance.ReportKill(attacker, this, weapon);
        }
        else
        {
            this.Die();
        }
    }

    public bool IsWeaponAllowed(Weapon weapon)
    {
        if (weapon == null)
        {
            return false;
        }

        if (GameManager.instance == null || GameManager.instance.gameMode == null)
        {
            return true;
        }

        return GameManager.instance.gameMode.IsWeaponAllowed(weapon);
    }

    public bool IsSpecialAbilityAllowed()
    {
        if (GameManager.instance == null || GameManager.instance.gameMode == null)
        {
            return true;
        }

        return GameManager.instance.gameMode.allowSpecialAbility;
    }

    public void Die()
    {
        this.stateMachine.ChangeState(this.playerDeathState);
    }

    public void Respawn(Vector3 position)
    {
        this.transform.position = position;
        this.rb.linearVelocity = Vector3.zero;
        this.stateMachine.ChangeState(this.playerIdleState);
        this.gameObject.SetActive(true);
    }
}

