using UnityEngine;

public abstract class CharacterAttackState : CharacterState
{
    protected float attackTimer;

    protected CharacterAttackState(PlayerController player) : base(player)
    {
    }

    protected abstract Weapon GetWeapon();

    public override void Enter()
    {
        base.Enter();

        Weapon weapon = this.GetWeapon();

        if (weapon == null)
        {
            this.player.stateMachine.ChangeState(this.player.playerIdleState);
            return;
        }

        this.attackTimer = weapon.attackDuration;

        this.player.rb.linearVelocity = new Vector3(
            0f,
            this.player.rb.linearVelocity.y,
            0f
        );

        weapon.Use(this.player);
    }

    public override void Update()
    {
        base.Update();

        this.FaceInputDirection();

        this.attackTimer -= Time.deltaTime;

        if (this.attackTimer <= 0f)
        {
            if (this.player.moveInput.sqrMagnitude > MOVEMENT_THRESHOLD_SQR)
            {
                this.player.stateMachine.ChangeState(this.player.playerMoveState);
            }
            else
            {
                this.player.stateMachine.ChangeState(this.player.playerIdleState);
            }
        }
    }

    public override void FixedUpdate()
    {
        base.FixedUpdate();

        this.player.rb.linearVelocity = new Vector3(
            0f,
            this.player.rb.linearVelocity.y,
            0f
        );
    }

    public override void Exit()
    {
        base.Exit();
    }
}

