using System.Collections.Generic;
using UnityEngine;

[RequireComponent(typeof(Rigidbody))]
public abstract class Projectile : MonoBehaviour
{
    [Header("Lifetime")]
    public float maxLifetime = 5f;

    [Header("Debug")]
    public bool showDebugArea;

    [Header("Explosion")]
    public bool explodeOnDestroy;
    public float explosionRadius = 3f;
    public float explosionHeightOffset = 1f;
    public LayerMask explosionHitMask;
    public LayerMask explosionLineOfSightMask = ~0;

    protected PlayerController owner;
    protected Weapon weapon;
    protected Rigidbody rb;

    public void Initialize(PlayerController owner, Weapon weapon)
    {
        this.owner = owner;
        this.weapon = weapon;
    }

    protected virtual void Awake()
    {
        this.rb = this.GetComponent<Rigidbody>();
    }

    protected virtual void Start()
    {
        Destroy(this.gameObject, this.maxLifetime);
    }

    private void OnTriggerEnter(Collider other)
    {
        IHittable hittable = other.GetComponentInParent<IHittable>();

        if (hittable != null)
        {
            PlayerController targetPlayer = other.GetComponentInParent<PlayerController>();

            if (targetPlayer == this.owner)
            {
                return;
            }

            hittable.OnHit(this.owner, this.weapon);
        }

        this.DestroyProjectile();
    }

    protected void DestroyProjectile()
    {
        if (this.explodeOnDestroy)
        {
            this.Explode();
        }

        Destroy(this.gameObject);
    }

    private void OnDrawGizmos()
    {
        if (!this.showDebugArea || !this.explodeOnDestroy)
        {
            return;
        }

        Gizmos.color = new Color(1f, 0.3f, 0f, 0.3f);
        Gizmos.DrawSphere(this.transform.position, this.explosionRadius);
        Gizmos.color = new Color(1f, 0.3f, 0f, 1f);
        Gizmos.DrawWireSphere(this.transform.position, this.explosionRadius);
    }

    private void Explode()
    {
        Vector3 origin = this.transform.position + Vector3.up * this.explosionHeightOffset;

        Collider[] colliders = Physics.OverlapSphere(
            origin,
            this.explosionRadius,
            this.explosionHitMask,
            QueryTriggerInteraction.Collide
        );

        HashSet<IHittable> hitTargets = new HashSet<IHittable>();

        foreach (Collider collider in colliders)
        {
            IHittable hittable = collider.GetComponentInParent<IHittable>();

            if (hittable == null)
            {
                continue;
            }

            if (hitTargets.Contains(hittable))
            {
                continue;
            }

            Vector3 targetPosition = collider.transform.position + Vector3.up * this.explosionHeightOffset;
            Vector3 direction = targetPosition - origin;
            float distance = direction.magnitude;

            if (distance > 0.0001f)
            {
                direction /= distance;

                if (Physics.Raycast(
                    origin,
                    direction,
                    out RaycastHit hit,
                    distance,
                    this.explosionLineOfSightMask,
                    QueryTriggerInteraction.Ignore
                ))
                {
                    IHittable hitHittable = hit.collider.GetComponentInParent<IHittable>();

                    if (hitHittable != hittable)
                    {
                        continue;
                    }
                }
            }

            hitTargets.Add(hittable);
            hittable.OnHit(this.owner, this.weapon);
        }
    }
}

