using UnityEngine;
using UnityEngine.UI;
using TMPro;

public class LobbyPlayerPanel : MonoBehaviour
{
    [SerializeField] private TextMeshProUGUI playerIndexText;
    [SerializeField] private TextMeshProUGUI statusText;
    [SerializeField] private TextMeshProUGUI deviceText;
    [SerializeField] private GameObject joinedGroup;
    [SerializeField] private GameObject emptyGroup;
    [SerializeField] private Image panelBackground;

    public void SetEmpty(int slotIndex)
    {
        if (this.playerIndexText != null)
        {
            this.playerIndexText.text = $"P{slotIndex + 1}";
        }

        if (this.statusText != null)
        {
            this.statusText.text = "Press Any Button to Join";
            this.statusText.color = Color.white;
        }

        if (this.deviceText != null)
        {
            this.deviceText.text = "";
        }

        if (this.emptyGroup != null)
        {
            this.emptyGroup.SetActive(true);
        }

        if (this.joinedGroup != null)
        {
            this.joinedGroup.SetActive(false);
        }

        if (this.panelBackground != null)
        {
            this.panelBackground.color = new Color(0.2f, 0.2f, 0.2f, 0.8f);
        }
    }

    public void SetPlayer(PlayerData data, string deviceName)
    {
        if (this.playerIndexText != null)
        {
            this.playerIndexText.text = $"P{data.playerIndex + 1}";
        }

        if (this.deviceText != null)
        {
            this.deviceText.text = deviceName;
        }

        if (this.joinedGroup != null)
        {
            this.joinedGroup.SetActive(true);
        }

        if (this.emptyGroup != null)
        {
            this.emptyGroup.SetActive(false);
        }

        this.SetReady(data.isReady);
    }

    public void SetReady(bool isReady)
    {
        if (this.statusText != null)
        {
            this.statusText.text = isReady ? "READY!" : "Press [D] to Ready";
            this.statusText.color = isReady ? Color.green : Color.yellow;
        }

        if (this.panelBackground != null)
        {
