using UnityEngine;
using UnityEngine.UI;
using TMPro;
using System.Collections.Generic;

public class GameModeSelector : MonoBehaviour
{
    [SerializeField] private TextMeshProUGUI modeNameText;
    [SerializeField] private TextMeshProUGUI modeInfoText;
    [SerializeField] private Button previousButton;
    [SerializeField] private Button nextButton;

    private List<GameMode> availableModes;
    private int currentIndex;

    public GameMode currentMode { get; private set; }

    public event System.Action<GameMode> OnModeChanged;

    public void Initialize(List<GameMode> modes)
    {
        if (modes == null || modes.Count == 0)
        {
            return;
        }

        this.availableModes = modes;
        this.currentIndex = 0;

        if (this.previousButton != null)
        {
            this.previousButton.onClick.AddListener(this.PreviousMode);
        }

        if (this.nextButton != null)
        {
            this.nextButton.onClick.AddListener(this.NextMode);
        }

        this.UpdateDisplay();
    }

    public void PreviousMode()
    {
        this.currentIndex--;

        if (this.currentIndex < 0)
        {
            this.currentIndex = this.availableModes.Count - 1;
        }

        this.UpdateDisplay();
    }

    public void NextMode()
    {
        this.currentIndex++;

        if (this.currentIndex >= this.availableModes.Count)
        {
            this.currentIndex = 0;
        }

        this.UpdateDisplay();
    }

    private void UpdateDisplay()
    {
        if (this.availableModes == null || this.availableModes.Count == 0)
        {
            return;
        }

        GameMode mode = this.availableModes[this.currentIndex];
        this.currentMode = mode;

        if (this.modeNameText != null)
        {
            this.modeNameText.text = mode.modeName;
        }

        if (this.modeInfoText != null)
        {
            this.modeInfoText.text = this.FormatModeInfo(mode);
        }

        this.OnModeChanged?.Invoke(this.currentMode);
    }

    private string FormatModeInfo(GameMode mode)
    {
        string weapons;

        if (mode.allowMeleeWeapons && mode.allowRangedWeapons && mode.allowThrowWeapons)
        {
            weapons = "All Weapons";
        }
        else if (!mode.allowMeleeWeapons && !mode.allowRangedWeapons && !mode.allowThrowWeapons)
        {
            weapons = "No Weapons";
        }
        else
        {
            List<string> allowed = new List<string>();

            if (mode.allowMeleeWeapons)
            {
                allowed.Add("Melee");
            }

            if (mode.allowRangedWeapons)
            {
                allowed.Add("Ranged");
            }

            if (mode.allowThrowWeapons)
            {
                allowed.Add("Throw");
            }

            weapons = string.Join(", ", allowed);
        }

        string specialAbility = mode.allowSpecialAbility ? "Allowed" : "Disabled";
        string winCondition = mode.useLastManStanding ? "Last Man Standing" : "Most Kills";

        return $"Rounds: {mode.numberOfRounds} | Duration: {mode.roundDuration}s\n" +
               $"Weapons: {weapons}\n" +
               $"Special Ability: {specialAbility}\n" +
               $"Win: {winCondition}";
    }

    private void OnDestroy()
    {
        if (this.previousButton != null)
        {
            this.previousButton.onClick.RemoveListener(this.PreviousMode);
        }

        if (this.nextButton != null)
        {
            this.nextButton.onClick.RemoveListener(this.NextMode);
        }
    }
}

