using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.InputSystem;
using UnityEngine.SceneManagement;

[RequireComponent(typeof(PlayerInputManager))]
public class GameManager : MonoBehaviour
{
    public static GameManager instance { get; private set; }

    [Header("Game Mode")]
    [SerializeField] private GameMode activeMode;

    [Header("Spawn Points")]
    [SerializeField] private List<Transform> spawnPoints = new List<Transform>();

    public GameMode gameMode => this.activeMode;
    public GameState currentState { get; private set; }
    public RoundHandler currentRound { get; private set; }
    public int currentRoundNumber { get; private set; }
    public List<PlayerData> players { get; private set; }

    private PlayerInputManager playerInputManager;
    private HashSet<int> trackedPlayerInstanceIds;

    public string gameSceneName { get; set; }

    public event System.Action<PlayerData> PlayerJoinedEvent;
    public event System.Action<PlayerData> PlayerLeftEvent;
    public event System.Action<PlayerData> PlayerReadyEvent;
    public event System.Action<KillRecord> OnPlayerKilled;
    public event System.Action<int> OnRoundStarted;
    public event System.Action<int> OnRoundEnded;
    public event System.Action OnGameStarted;
    public event System.Action OnGameOver;

    private void Awake()
    {
        if (instance != null && instance != this)
        {
            Destroy(this.gameObject);
            return;
        }

        instance = this;
        DontDestroyOnLoad(this.gameObject);

        this.playerInputManager = GetComponent<PlayerInputManager>();

        this.players = new List<PlayerData>();
        this.trackedPlayerInstanceIds = new HashSet<int>();
        this.currentState = GameState.Lobby;
        this.currentRoundNumber = 0;

        this.playerInputManager.EnableJoining();
    }

    private void Update()
    {
        if (this.currentState != GameState.Lobby)
        {
            return;
        }

        this.PollForNewPlayers();
    }

    private void PollForNewPlayers()
    {
        var allPlayers = PlayerInput.all;

        for (int i = 0; i < allPlayers.Count; i++)
        {
            PlayerInput pi = allPlayers[i];
            int instanceId = pi.gameObject.GetInstanceID();

            if (this.trackedPlayerInstanceIds.Contains(instanceId))
            {
                continue;
            }

            this.trackedPlayerInstanceIds.Add(instanceId);

            int index = pi.playerIndex;
            PlayerData data = new PlayerData(index);

            PlayerController controller = pi.GetComponent<PlayerController>();

            if (controller != null)
            {
                data.controller = controller;
                controller.playerData = data;
                controller.playerIndex = index;

                DontDestroyOnLoad(controller.gameObject);
                this.HidePlayer(controller);
            }

            this.players.Add(data);
            this.PlayerJoinedEvent?.Invoke(data);
        }
    }

    private void OnDestroy()
    {
    }

    public void SetGameMode(GameMode mode)
    {
        if (this.currentState != GameState.Lobby)
        {
            return;
        }

        this.activeMode = mode;
    }

    public PlayerData GetPlayerData(int playerIndex)
    {
        for (int i = 0; i < this.players.Count; i++)
        {
            if (this.players[i].playerIndex == playerIndex)
            {
                return this.players[i];
            }
        }

        return null;
    }

    public PlayerData GetPlayerData(PlayerController controller)
    {
        for (int i = 0; i < this.players.Count; i++)
        {
            if (this.players[i].controller == controller)
            {
                return this.players[i];
            }
        }

        return null;
    }

    public void TogglePlayerReady(int playerIndex)
    {
        PlayerData data = this.GetPlayerData(playerIndex);

        if (data == null)
        {
            return;
        }

        if (!data.isReady)
        {
            data.isReady = true;
            this.PlayerReadyEvent?.Invoke(data);
        }
        else if (playerIndex == 0 && this.AreAllPlayersReady())
        {
            this.StartGameWithScene(this.gameSceneName);
        }
        else
        {
            data.isReady = false;
            this.PlayerReadyEvent?.Invoke(data);
        }
    }

    public bool AreAllPlayersReady()
    {
        if (this.players.Count < 2)
        {
            return false;
        }

        for (int i = 0; i < this.players.Count; i++)
        {
            if (!this.players[i].isReady)
            {
                return false;
            }
        }

        return true;
    }

    private void HidePlayer(PlayerController controller)
    {
        if (controller == null)
        {
            return;
        }

        controller.rb.isKinematic = true;
        controller.rb.linearVelocity = Vector3.zero;

        Renderer[] renderers = controller.GetComponentsInChildren<Renderer>();
        for (int i = 0; i < renderers.Length; i++)
        {
            renderers[i].enabled = false;
        }

        Collider col = controller.GetComponent<Collider>();
        if (col != null)
        {
            col.enabled = false;
        }
    }

    private void ShowPlayer(PlayerController controller)
    {
        if (controller == null)
        {
            return;
        }

        controller.rb.isKinematic = false;

        Renderer[] renderers = controller.GetComponentsInChildren<Renderer>();
        for (int i = 0; i < renderers.Length; i++)
        {
            renderers[i].enabled = true;
        }

        Collider col = controller.GetComponent<Collider>();
        if (col != null)
        {
            col.enabled = true;
        }
    }

    public void StartGame()
    {
        if (this.currentState != GameState.Lobby)
        {
            return;
        }

        if (this.players.Count < 2)
        {
            return;
        }

        this.playerInputManager.DisableJoining();
        this.currentRoundNumber = 0;
        this.OnGameStarted?.Invoke();
        this.StartRound();
    }

    public void RegisterSpawnPoints(List<Transform> points)
    {
        this.spawnPoints = points;
    }

    public void StartGameWithScene(string sceneName)
    {
        if (this.currentState != GameState.Lobby)
        {
            return;
        }

        if (this.players.Count < 2)
        {
            return;
        }

        for (int i = 0; i < this.players.Count; i++)
        {
            if (this.players[i].controller != null)
            {
                this.ShowPlayer(this.players[i].controller);
            }
        }

        this.playerInputManager.DisableJoining();
        SceneManager.sceneLoaded += this.OnGameSceneLoaded;
        SceneManager.LoadScene(sceneName);
    }

    private void OnGameSceneLoaded(Scene scene, LoadSceneMode loadMode)
    {
        SceneManager.sceneLoaded -= this.OnGameSceneLoaded;
        this.currentRoundNumber = 0;
        this.OnGameStarted?.Invoke();
        this.StartRound();
    }

    private void StartRound()
    {
        this.currentRoundNumber++;
        this.currentState = GameState.RoundStarting;

        this.currentRound = this.gameObject.AddComponent<RoundHandler>();
        this.currentRound.Initialize(this.activeMode, this.players.Count);

        this.OnRoundStarted?.Invoke(this.currentRoundNumber);

        StartCoroutine(this.RoundStartDelayCoroutine());
    }

    private IEnumerator RoundStartDelayCoroutine()
    {
        yield return new WaitForSeconds(this.activeMode.roundStartDelay);

        this.currentState = GameState.RoundActive;
        this.currentRound.StartRound();
    }

    public void EndRound()
    {
        if (this.currentState != GameState.RoundActive)
        {
            return;
        }

        this.currentState = GameState.RoundEnding;

        if (this.currentRound != null)
        {
            this.currentRound.StopRound();
        }

        this.OnRoundEnded?.Invoke(this.currentRoundNumber);

        StartCoroutine(this.RoundEndDelayCoroutine());
    }

    private IEnumerator RoundEndDelayCoroutine()
    {
        yield return new WaitForSeconds(this.activeMode.roundEndDelay);

        if (this.currentRound != null)
        {
            Destroy(this.currentRound);
            this.currentRound = null;
        }

        if (this.currentRoundNumber >= this.activeMode.numberOfRounds)
        {
            this.EndGame();
        }
        else
        {
            this.RespawnAllPlayers();
            this.StartRound();
        }
    }

    private void EndGame()
    {
        this.currentState = GameState.GameOver;
        this.OnGameOver?.Invoke();
    }

    public void ReturnToLobby(string lobbySceneName = null)
    {
        this.currentState = GameState.Lobby;
        this.currentRoundNumber = 0;

        for (int i = 0; i < this.players.Count; i++)
        {
            this.players[i].ResetForNewGame();
        }

        this.playerInputManager.EnableJoining();

        if (!string.IsNullOrEmpty(lobbySceneName))
        {
            SceneManager.LoadScene(lobbySceneName);
        }
    }

    public void ReportKill(PlayerController attacker, PlayerController victim, Weapon weapon)
    {
        if (this.currentState != GameState.RoundActive)
        {
            return;
        }

        bool isSuicide = attacker == victim;

        KillRecord record = new KillRecord(attacker, victim, weapon, Time.time, isSuicide);

        if (this.currentRound != null)
        {
            this.currentRound.RecordKill(record);
        }

        PlayerData attackerData = this.GetPlayerData(attacker);
        PlayerData victimData = this.GetPlayerData(victim);

        if (isSuicide)
        {
            if (victimData != null)
            {
                victimData.RecordSuicide(this.activeMode.suicidePenalty);
            }
        }
        else
        {
            if (attackerData != null)
            {
                attackerData.RecordKill(this.activeMode.pointsPerKill);
            }

            if (victimData != null)
            {
                victimData.RecordDeath();
            }
        }

        victim.Die();

        this.OnPlayerKilled?.Invoke(record);
    }

    public void RequestRespawn(PlayerController player)
    {
        if (this.currentState != GameState.RoundActive)
        {
            return;
        }

        StartCoroutine(this.RespawnCoroutine(player));
    }

    private IEnumerator RespawnCoroutine(PlayerController player)
    {
        yield return new WaitForSeconds(this.activeMode.respawnDelay);

        if (this.currentState != GameState.RoundActive)
        {
            yield break;
        }

        Vector3 spawnPosition = this.GetSpawnPosition();
        player.Respawn(spawnPosition);
    }

    private void RespawnAllPlayers()
    {
        for (int i = 0; i < this.players.Count; i++)
        {
            PlayerController controller = this.players[i].controller;
            if (controller != null)
            {
                Vector3 spawnPosition = this.GetSpawnPosition();
                controller.Respawn(spawnPosition);
            }
        }
    }

    private Vector3 GetSpawnPosition()
    {
        if (this.spawnPoints.Count > 0)
        {
            int index = Random.Range(0, this.spawnPoints.Count);
            return this.spawnPoints[index].position;
        }

        return Vector3.zero;
    }

    public int GetAlivePlayerCount()
    {
        int count = 0;

        for (int i = 0; i < this.players.Count; i++)
        {
            PlayerController controller = this.players[i].controller;
            if (controller != null && controller.stateMachine.currentState != controller.playerDeathState)
            {
                count++;
            }
        }

        return count;
    }
}

