using UnityEngine;
using UnityEngine.UI;
using UnityEngine.InputSystem;
using TMPro;
using System.Collections.Generic;

public class LobbyManager : MonoBehaviour
{
    [Header("Player Panels")]
    [SerializeField] private List<LobbyPlayerPanel> playerPanels;

    [Header("Game Mode")]
    [SerializeField] private GameModeSelector gameModeSelector;
    [SerializeField] private List<GameMode> availableModes;

    [Header("Start Game")]
    [SerializeField] private Button startButton;
    [SerializeField] private TextMeshProUGUI startButtonText;

    [Header("Scene")]
    [SerializeField] private string gameSceneName = "TestMap";

    private void Start()
    {
        for (int i = 0; i < this.playerPanels.Count; i++)
        {
            this.playerPanels[i].SetEmpty(i);
        }

        if (this.gameModeSelector != null)
        {
            this.gameModeSelector.Initialize(this.availableModes);
            this.gameModeSelector.OnModeChanged += this.OnGameModeChanged;
        }

        if (this.startButton != null)
        {
            this.startButton.interactable = false;
        }

        if (GameManager.instance != null)
        {
            GameManager.instance.gameSceneName = this.gameSceneName;
        }

        this.RefreshAllPanels();
        this.UpdateStartButton();

        if (GameManager.instance != null && this.gameModeSelector != null && this.gameModeSelector.currentMode != null)
        {
            GameManager.instance.SetGameMode(this.gameModeSelector.currentMode);
        }
    }

    private void Update()
    {
        if (GameManager.instance == null)
        {
            return;
        }

        this.RefreshAllPanels();
        this.UpdateStartButton();
    }

    private void OnDestroy()
    {
        if (this.gameModeSelector != null)
        {
            this.gameModeSelector.OnModeChanged -= this.OnGameModeChanged;
        }
    }

    private void OnGameModeChanged(GameMode mode)
    {
        if (GameManager.instance != null)
        {
            GameManager.instance.SetGameMode(mode);
        }
    }

    private void RefreshAllPanels()
    {
        if (GameManager.instance == null)
        {
            return;
        }

        for (int i = 0; i < this.playerPanels.Count; i++)
        {
            PlayerData data = GameManager.instance.GetPlayerData(i);

            if (data != null && data.controller != null)
            {
                string deviceName = this.GetDeviceName(data.controller.playerInput);
                this.playerPanels[i].SetPlayer(data, deviceName);
            }
            else
            {
                this.playerPanels[i].SetEmpty(i);
            }
        }
    }

    private string GetDeviceName(PlayerInput playerInput)
    {
        if (playerInput == null || playerInput.devices.Count == 0)
        {
            return "Unknown";
        }

        if (playerInput.devices[0] is UnityEngine.InputSystem.Gamepad)
        {
            return "Controller";
        }

        return "Keyboard";
    }

    private void OnGUI()
    {
        GUIStyle style = new GUIStyle(GUI.skin.label);
        style.fontSize = 20;
        style.normal.textColor = Color.red;

        string gmStatus = GameManager.instance == null ? "NULL" : "OK";
        string playerCount = GameManager.instance != null && GameManager.instance.players != null
            ? GameManager.instance.players.Count.ToString()
            : "N/A";
        string state = GameManager.instance != null ? GameManager.instance.currentState.ToString() : "N/A";

        GUI.Label(new Rect(10, 10, 600, 30), $"GM: {gmStatus} | Players: {playerCount} | State: {state}", style);
    }

    private void UpdateStartButton()
    {
        if (this.startButtonText == null)
        {
            return;
        }

        if (GameManager.instance == null || GameManager.instance.players.Count < 2)
        {
            this.startButtonText.text = "WAITING FOR PLAYERS...";
            this.startButtonText.color = Color.gray;
            return;
        }

        if (GameManager.instance.AreAllPlayersReady())
        {
            this.startButtonText.text = "P1 - PRESS [ATTACK] TO START!";
            this.startButtonText.color = Color.green;
            return;
        }

        this.startButtonText.text = "WAITING FOR READY...";
        this.startButtonText.color = Color.white;
    }
}

