193â†’                    }
194â†’                    _instance.StopServer();
195â†’                    break;
196â†’                case PlayModeStateChange.EnteredEditMode:
197â†’                    // Back in edit mode, restart if we were running
198â†’                    if (SessionState.GetBool(SESSION_KEY_WAS_RUNNING, false) && !_instance.IsListening)
199â†’                    {
200â†’                        _instance.StartServer();
201â†’                    }
202â†’                    break;
203â†’            }
204â†’        }
