 51â†’        {
 52â†’            float x = value?["x"]?.ToObject<float>() ?? 0f;
 53â†’            float y = value?["y"]?.ToObject<float>() ?? 0f;
 54â†’
 55â†’            // Use the PlayerInput component to inject input via the Input System
 56â†’            var playerInput = controller.playerInput;
 57â†’            if (playerInput == null)
 58â†’            {
 59â†’                return PlaytestSocketHandler.CreateErrorResponse("PlayerInput component not found", "input_error");
 60â†’            }
 61â†’
 62â†’            // Find the device paired to this player
 63â†’            var devices = playerInput.devices;
 64â†’            if (devices.Count == 0)
 65â†’            {
 66â†’                // If no device is paired, try using InputSystem to queue a virtual gamepad event
 67â†’                return SimulateMoveViaAction(controller, x, y, duration, playerIndex);
 68â†’            }
 69â†’
 70â†’            // Try to find a gamepad among paired devices
 71â†’            Gamepad gamepad = null;
 72â†’            foreach (var device in devices)
 73â†’            {
 74â†’                if (device is Gamepad gp) { gamepad = gp; break; }
 75â†’            }
 76â†’
 77â†’            if (gamepad != null)
 78â†’            {
 79â†’                // Change the gamepad's left stick state directly
 80â†’                InputState.Change(gamepad.leftStick, new Vector2(x, y));
 81â†’
 82â†’                if (duration > 0f)
 83â†’                {
 84â†’                    ScheduleMoveReset(gamepad, playerIndex, duration);
 85â†’                }
 86â†’
 87â†’                return new JObject
 88â†’                {
 89â†’                    ["success"] = true,
 90â†’                    ["action"] = "move",
 91â†’                    ["playerIndex"] = playerIndex,
 92â†’                    ["appliedValue"] = new JObject { ["x"] = x, ["y"] = y },
 93â†’                    ["duration"] = duration,
 94â†’                    ["method"] = "gamepad_stick"
 95â†’                };
 96â†’            }
 97â†’
 98â†’            // Fallback to action-based simulation
 99â†’            return SimulateMoveViaAction(controller, x, y, duration, playerIndex);
100â†’        }
101â†’
102â†’        private static JObject SimulateMoveViaAction(PlayerController controller, float x, float y, float duration, int playerIndex)
103â†’        {
104â†’            // Directly set the moveInput through the PlayerInput action
105â†’            var playerInput = controller.playerInput;
106â†’            if (playerInput != null)
107â†’            {
108â†’                var moveAction = playerInput.actions?.FindAction("Move");
109â†’                if (moveAction != null)
110â†’                {
111â†’                    // We can't easily inject values into actions without a device,
112â†’                    // so use reflection to set moveInput directly
113â†’                    var moveInputField = typeof(PlayerController).GetProperty("moveInput");
114â†’                    if (moveInputField != null && moveInputField.CanWrite)
115â†’                    {
116â†’                        moveInputField.SetValue(controller, new Vector2(x, y));
117â†’                    }
118â†’                    else
119â†’                    {
120â†’                        // Use the private backing field via reflection
121â†’                        var field = typeof(PlayerController).GetField("<moveInput>k__BackingField",
122â†’                            System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
123â†’                        if (field != null)
124â†’                        {
125â†’                            field.SetValue(controller, new Vector2(x, y));
126â†’                        }
127â†’                    }
128â†’
129â†’                    if (duration > 0f)
130â†’                    {
131â†’                        _activeSimulations[playerIndex] = new InputSimulationState
132â†’                        {
133â†’                            controller = controller,
134â†’                            action = "move",
135â†’                            endTime = Time.realtimeSinceStartup + duration,
136â†’                            moveValue = new Vector2(x, y)
137â†’                        };
138â†’
139â†’                        UnityEditor.EditorApplication.update += CheckSimulationExpiry;
140â†’                    }
141â†’
142â†’                    return new JObject
143â†’                    {
144â†’                        ["success"] = true,
145â†’                        ["action"] = "move",
146â†’                        ["playerIndex"] = playerIndex,
147â†’                        ["appliedValue"] = new JObject { ["x"] = x, ["y"] = y },
148â†’                        ["duration"] = duration,
149â†’                        ["method"] = "reflection"
150â†’                    };
151â†’                }
152â†’            }
153â†’
154â†’            return PlaytestSocketHandler.CreateErrorResponse("Could not inject movement input", "input_error");
155â†’        }
156â†’
157â†’        private static JObject SimulateButtonPress(PlayerController controller, string callbackName)
158â†’        {
159â†’            // Use the PlayerInput component's device to simulate a button press
160â†’            var playerInput = controller.playerInput;
161â†’            if (playerInput != null)
162â†’            {
163â†’                var devices = playerInput.devices;
164â†’                Gamepad gamepad = null;
165â†’                foreach (var device in devices)
166â†’                {
167â†’                    if (device is Gamepad gp) { gamepad = gp; break; }
168â†’                }
169â†’
170â†’                if (gamepad != null)
171â†’                {
172â†’                    // Map callback names to gamepad buttons
173â†’                    InputControl button = null;
174â†’                    switch (callbackName)
175â†’                    {
176â†’                        case "OnMeleeAttack": button = gamepad.buttonEast; break;
177â†’                        case "OnRangedAttack": button = gamepad.buttonSouth; break;
178â†’                        case "OnThrowAttack": button = gamepad.buttonWest; break;
179â†’                        case "OnSpecialAbility": button = gamepad.buttonNorth; break;
180â†’                    }
181â†’
182â†’                    if (button is ButtonControl btn)
183â†’                    {
184â†’                        // Press then release
185â†’                        InputState.Change(btn, 1f);
186â†’
187â†’                        UnityEditor.EditorApplication.delayCall += () =>
188â†’                        {
189â†’                            InputState.Change(btn, 0f);
190â†’                        };
191â†’
192â†’                        return new JObject
193â†’                        {
194â†’                            ["success"] = true,
195â†’                            ["action"] = callbackName.Replace("On", "").ToLower(),
196â†’                            ["playerIndex"] = controller.playerIndex,
197â†’                            ["method"] = "gamepad_button"
198â†’                        };
199â†’                    }
200â†’                }
201â†’            }
202â†’
203â†’            // Fallback: use reflection to set the pressed bool directly
204â†’            string fieldName = callbackName switch
205â†’            {
206â†’                "OnMeleeAttack" => "meleeAttackPressed",
207â†’                "OnRangedAttack" => "rangedAttackPressed",
208â†’                "OnThrowAttack" => "throwAttackPressed",
209â†’                "OnSpecialAbility" => "specialAbilityPressed",
210â†’                _ => null
211â†’            };
212â†’
213â†’            if (fieldName != null)
214â†’            {
215â†’                var prop = typeof(PlayerController).GetProperty(fieldName);
216â†’                if (prop != null)
217â†’                {
218â†’                    // These are auto-properties with private set, use backing field
219â†’                    var field = typeof(PlayerController).GetField($"<{fieldName}>k__BackingField",
220â†’                        System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
221â†’                    if (field != null)
222â†’                    {
223â†’                        field.SetValue(controller, true);
224â†’                        return new JObject
225â†’                        {
226â†’                            ["success"] = true,
227â†’                            ["action"] = callbackName.Replace("On", "").ToLower(),
228â†’                            ["playerIndex"] = controller.playerIndex,
229â†’                            ["method"] = "reflection"
230â†’                        };
231â†’                    }
232â†’                }
233â†’            }
234â†’
235â†’            return PlaytestSocketHandler.CreateErrorResponse($"Could not simulate {callbackName}", "input_error");
236â†’        }
237â†’
238â†’        private static void ScheduleMoveReset(Gamepad gamepad, int playerIndex, float duration)
239â†’        {
240â†’            float endTime = Time.realtimeSinceStartup + duration;
241â†’
242â†’            void ResetCheck()
243â†’            {
244â†’                if (Time.realtimeSinceStartup >= endTime)
245â†’                {
246â†’                    UnityEditor.EditorApplication.update -= ResetCheck;
247â†’                    try
248â†’                    {
249â†’                        InputState.Change(gamepad.leftStick, Vector2.zero);
250â†’                    }
251â†’                    catch (Exception) { }
252â†’                }
253â†’            }
254â†’
255â†’            UnityEditor.EditorApplication.update += ResetCheck;
256â†’        }
257â†’
258â†’        private static void CheckSimulationExpiry()
259â†’        {
260â†’            var expired = new List<int>();
261â†’
262â†’            foreach (var kvp in _activeSimulations)
263â†’            {
264â†’                if (Time.realtimeSinceStartup >= kvp.Value.endTime)
265â†’                {
266â†’                    expired.Add(kvp.Key);
267â†’
268â†’                    // Reset the move input
269â†’                    var field = typeof(PlayerController).GetField("<moveInput>k__BackingField",
270â†’                        System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
271â†’                    if (field != null && kvp.Value.controller != null)
272â†’                    {
273â†’                        field.SetValue(kvp.Value.controller, Vector2.zero);
274â†’                    }
275â†’                }
276â†’            }
277â†’
278â†’            foreach (var key in expired)
279â†’            {
280â†’                _activeSimulations.Remove(key);
281â†’            }
282â†’
283â†’            if (_activeSimulations.Count == 0)
284â†’            {
285â†’                UnityEditor.EditorApplication.update -= CheckSimulationExpiry;
286â†’            }
287â†’        }
288â†’
289â†’        private static PlayerController FindPlayerController(int playerIndex)
290â†’        {
291â†’            // Try GameManager first
292â†’            var gm = GameManager.instance;
293â†’            if (gm != null && gm.players != null)
294â†’            {
295â†’                for (int i = 0; i < gm.players.Count; i++)
296â†’                {
297â†’                    if (gm.players[i].playerIndex == playerIndex && gm.players[i].controller != null)
298â†’                    {
299â†’                        return gm.players[i].controller;
300â†’                    }
301â†’                }
302â†’            }
303â†’
304â†’            // Fallback: find all PlayerControllers in scene
305â†’            var controllers = UnityEngine.Object.FindObjectsByType<PlayerController>(FindObjectsSortMode.None);
306â†’            foreach (var ctrl in controllers)
307â†’            {
308â†’                if (ctrl.playerIndex == playerIndex)
309â†’                {
310â†’                    return ctrl;
311â†’                }
312â†’            }
313â†’
314â†’            return null;
315â†’        }
316â†’    }
317â†’}
