10â†’import { registerRecordVideoTool } from './tools/recordVideoTool.js';
11â†’
12â†’// Initialize loggers
13â†’const serverLogger = new Logger('Server', LogLevel.INFO);
14â†’const unityLogger = new Logger('Unity', LogLevel.INFO);
15â†’const toolLogger = new Logger('Tools', LogLevel.INFO);
16â†’
17â†’// Initialize the MCP server
18â†’const server = new McpServer(
19â†’  {
20â†’    name: "MCP Playtest Server",
21â†’    version: "1.0.0"
22â†’  },
23â†’  {
24â†’    capabilities: {
25â†’      tools: {}
26â†’    }
27â†’  }
28â†’);
29â†’
30â†’// Initialize the Unity bridge
31â†’const playtestUnity = new PlaytestUnity(unityLogger);
