34â†’registerPlayModeControlTool(server, playtestUnity, toolLogger);
35â†’registerCaptureScreenshotTool(server, playtestUnity, toolLogger);
36â†’registerSimulateInputTool(server, playtestUnity, toolLogger);
37â†’registerQueryGameStateTool(server, playtestUnity, toolLogger);
38â†’registerGetConsoleLogsTool(server, playtestUnity, toolLogger);
39â†’registerRecordVideoTool(server, playtestUnity, toolLogger);
