41â†’// Server startup
42â†’async function startServer() {
43â†’  try {
44â†’    const stdioTransport = new StdioServerTransport();
45â†’    await server.connect(stdioTransport);
46â†’    serverLogger.info('MCP Playtest Server started');
47â†’
48â†’    const clientName = server.server.getClientVersion()?.name || 'Unknown MCP Client';
49â†’    serverLogger.info(`Connected MCP client: ${clientName}`);
50â†’
51â†’    await playtestUnity.start(clientName);
52â†’  } catch (error) {
53â†’    serverLogger.error('Failed to start server', error);
54â†’    process.exit(1);
55â†’  }
56â†’}
57â†’
58â†’// Graceful shutdown
59â†’let isShuttingDown = false;
60â†’async function shutdown() {
61â†’  if (isShuttingDown) return;
62â†’  isShuttingDown = true;
63â†’
64â†’  try {
65â†’    serverLogger.info('Shutting down...');
66â†’    await playtestUnity.stop();
67â†’    await server.close();
68â†’  } catch (error) {
69â†’    // Ignore errors during shutdown
70â†’  }
71â†’  process.exit(0);
72â†’}
73â†’
74â†’// Start
75â†’startServer();
76â†’
77â†’// Handle shutdown signals
78â†’process.on('SIGINT', shutdown);
79â†’process.on('SIGTERM', shutdown);
80â†’process.on('SIGHUP', shutdown);
81â†’process.stdin.on('close', shutdown);
82â†’process.stdin.on('end', shutdown);
83â†’process.stdin.on('error', shutdown);
84â†’
85â†’process.on('uncaughtException', (error: NodeJS.ErrnoException) => {
86â†’  if (error.code === 'EPIPE' || error.code === 'EOF' || error.code === 'ERR_USE_AFTER_CLOSE') {
87â†’    shutdown();
88â†’    return;
89â†’  }
90â†’  serverLogger.error('Uncaught exception', error);
91â†’  process.exit(1);
92â†’});
93â†’
94â†’process.on('unhandledRejection', (reason) => {
95â†’  serverLogger.error('Unhandled rejection', reason);
96â†’  process.exit(1);
97â†’});
