 69â†’                    }
 70â†’                    EditorApplication.isPaused = true;
 71â†’                    return new JObject
 72â†’                    {
 73â†’                        ["success"] = true,
 74â†’                        ["message"] = "Play Mode paused",
 75â†’                        ["isPlaying"] = true,
 76â†’                        ["isPaused"] = true
 77â†’                    };
 78â†’
 79â†’                case "unpause":
 80â†’                    if (!EditorApplication.isPlaying)
 81â†’                    {
 82â†’                        return PlaytestSocketHandler.CreateErrorResponse("Cannot unpause: not in Play Mode", "invalid_state");
 83â†’                    }
 84â†’                    EditorApplication.isPaused = false;
 85â†’                    return new JObject
 86â†’                    {
