 1â†’import * as z from 'zod';
 2â†’import { Logger } from '../utils/logger.js';
 3â†’import { PlaytestUnity } from '../unity/playtestUnity.js';
 4â†’import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
 5â†’import { McpPlaytestError, ErrorType } from '../utils/errors.js';
 6â†’import { CallToolResult } from '@modelcontextprotocol/sdk/types.js';
 7â†’
 8â†’const toolName = 'play_mode_control';
 9â†’const toolDescription = 'Control Unity Play Mode: enter, exit, pause, unpause, or step one frame';
10â†’const paramsSchema = z.object({
11â†’  action: z.enum(['enter', 'exit', 'pause', 'unpause', 'step']).describe('The play mode action to perform')
12â†’});
13â†’
14â†’export function registerPlayModeControlTool(server: McpServer, playtestUnity: PlaytestUnity, logger: Logger) {
15â†’  logger.info(`Registering tool: ${toolName}`);
16â†’
17â†’  server.tool(
18â†’    toolName,
19â†’    toolDescription,
20â†’    paramsSchema.shape,
21â†’    async (params: any) => {
22â†’      try {
23â†’        logger.info(`Executing tool: ${toolName}`, params);
24â†’        const result = await toolHandler(playtestUnity, params);
25â†’        logger.info(`Tool execution successful: ${toolName}`);
26â†’        return result;
27â†’      } catch (error) {
28â†’        logger.error(`Tool execution failed: ${toolName}`, error);
29â†’        throw error;
30â†’      }
31â†’    }
32â†’  );
33â†’}
34â†’
35â†’async function toolHandler(playtestUnity: PlaytestUnity, params: any): Promise<CallToolResult> {
36â†’  const action = params.action as string;
37â†’  const causesReload = action === 'enter' || action === 'exit';
38â†’
39â†’  try {
40â†’    const response = await playtestUnity.sendRequest({
41â†’      method: toolName,
42â†’      params
43â†’    });
44â†’
45â†’    if (!response.success) {
46â†’      throw new McpPlaytestError(ErrorType.TOOL_EXECUTION, response.message || 'Failed to control play mode');
47â†’    }
48â†’
49â†’    return {
50â†’      content: [{
51â†’        type: 'text',
52â†’        text: JSON.stringify(response, null, 2)
53â†’      }]
54â†’    };
55â†’  } catch (error) {
56â†’    // Enter/exit triggers a Unity domain reload which kills the WebSocket.
57â†’    // A disconnection or timeout during these actions means the action succeeded.
58â†’    if (causesReload && error instanceof McpPlaytestError &&
59â†’        (error.type === ErrorType.TIMEOUT || error.type === ErrorType.CONNECTION)) {
60â†’      const entering = action === 'enter';
61â†’      return {
62â†’        content: [{
63â†’          type: 'text',
64â†’          text: JSON.stringify({
65â†’            success: true,
66â†’            message: entering ? 'Entering Play Mode (domain reload in progress)' : 'Exiting Play Mode (domain reload in progress)',
67â†’            isPlaying: entering,
68â†’            isPaused: false,
69â†’            note: 'Unity is reloading. Wait a moment before sending the next command.'
70â†’          }, null, 2)
71â†’        }]
72â†’      };
73â†’    }
74â†’    throw error;
75â†’  }
76â†’}
