## How to Add a "join_player" Command

### Architecture for join_player

The challenge: PlayerInputManager auto-spawns players on **real device input**. To programmatically join, you'd need to either:

**Option A: Force PlayerInputManager to spawn** (simplest)
- Inject a fake button press to trigger auto-spawn
- Let the normal join flow work

**Option B: Direct API call** (more reliable)
- Call `PlayerInputManager.JoinPlayer()` if available, or
- Manually instantiate a player prefab and register with GameManager

---

### Implementation Steps

#### Step 1: Add C# Tool (Assets/Editor/McpPlaytest/Tools/JoinPlayerTool.cs)

```csharp
// Pattern from PlayModeControlTool.cs and SimulateInputTool.cs
public class JoinPlayerTool : PlaytestToolBase
{
  public JoinPlayerTool() {
    Name = "join_player";
    Description = "Join a new player to the game (only in Lobby state)";
    IsAsync = false;
  }

  public override JObject Execute(JObject parameters) {
    var gm = GameManager.instance;
    if (gm == null) {
      return PlaytestSocketHandler.CreateErrorResponse(
        "GameManager not found",
        "invalid_state"
      );
    }

    if (gm.currentState != GameState.Lobby) {
      return PlaytestSocketHandler.CreateErrorResponse(
        "Cannot join: game not in Lobby state",
        "invalid_state"
      );
    }

    int maxPlayers = gm.gameMode?.maxPlayers ?? 4;
    int currentCount = gm.players?.Count ?? 0;

    if (currentCount >= maxPlayers) {
      return PlaytestSocketHandler.CreateErrorResponse(
        $"Max players ({maxPlayers}) reached",
        "validation_error"
      );
    }

    // Approach A: Simulate button press to trigger auto-spawn
    var result = InputSimulator.SimulateJoin();

    return new JObject {
      ["success"] = true,
      ["message"] = "Player join initiated",
      ["playerCount"] = gm.players.Count,
      ["joinMethod"] = result
    };
  }
}
```

#### Step 2: Add InputSimulator.SimulateJoin() method

```csharp
// InputSimulator.cs
public static JObject SimulateJoin() {
  var playerInputMgr = GameManager.instance?.GetComponent<PlayerInputManager>();
  if (playerInputMgr == null) {
    return PlaytestSocketHandler.CreateErrorResponse(
      "PlayerInputManager not found",
      "invalid_state"
    );
  }

  // Trigger join by simulating a "Join" action (if defined in Controls.inputactions)
  // or by injecting a device event

  // Option 1: If "Join" action exists in input map
  var devices = InputSystem.devices;
  if (devices.Count > 0 && devices[0] is Gamepad gamepad) {
    // Simulate any button press (or dedicated join button)
    InputState.Change(gamepad.startButton, 1f);
    EditorApplication.delayCall += () => {
      InputState.Change(gamepad.startButton, 0f);
    };
  }

  return new JObject { ["method"] = "button_press" };
}
```

#### Step 3: Register in PlaytestServer.cs

```csharp
// PlaytestServer.cs:136-161 (RegisterTools method)
private void RegisterTools() {
  // ... existing tools ...

  var joinPlayer = new JoinPlayerTool();
  _tools.Add(joinPlayer.Name, joinPlayer);
}
```

#### Step 4: Add TypeScript Tool (Assets/Editor/McpPlaytest/Server~/src/tools/joinPlayerTool.ts)

```typescript
import * as z from 'zod';
import { Logger } from '../utils/logger.js';
import { PlaytestUnity } from '../unity/playtestUnity.js';
import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
import { McpPlaytestError, ErrorType } from '../utils/errors.js';
import { CallToolResult } from '@modelcontextprotocol/sdk/types.js';

const toolName = 'join_player';
const toolDescription = 'Join a new player to the game (only in Lobby state)';
const paramsSchema = z.object({
  // Optional: could add parameters like playerName, characterType, etc
});

export function registerJoinPlayerTool(server: McpServer, playtestUnity: PlaytestUnity, logger: Logger) {
  logger.info(`Registering tool: ${toolName}`);

  server.tool(
    toolName,
    toolDescription,
    paramsSchema.shape,
    async (params: any) => {
      try {
        logger.info(`Executing tool: ${toolName}`, params);
        const result = await toolHandler(playtestUnity, params);
        logger.info(`Tool execution successful: ${toolName}`);
        return result;
      } catch (error) {
        logger.error(`Tool execution failed: ${toolName}`, error);
        throw error;
      }
    }
  );
}

async function toolHandler(playtestUnity: PlaytestUnity, params: any): Promise<CallToolResult> {
  const response = await playtestUnity.sendRequest({
    method: toolName,
    params
  });

  if (!response.success) {
    throw new McpPlaytestError(ErrorType.TOOL_EXECUTION, response.message || 'Failed to join player');
  }

  return {
    content: [{
      type: 'text',
      text: JSON.stringify(response, null, 2)
    }]
  };
}
```

#### Step 5: Register in index.ts

```typescript
// src/index.ts
import { registerJoinPlayerTool } from './tools/joinPlayerTool.js';  // Add import

// In registerPlayModeControlTool() area, add:
registerJoinPlayerTool(server, playtestUnity, toolLogger);
```

