using System;
using System.Threading.Tasks;
using Newtonsoft.Json.Linq;
using UnityEditor;
using UnityEngine;
using UnityEngine.InputSystem;

namespace McpPlaytest
{
    public class JoinPlayerTool : PlaytestToolBase
    {
        public JoinPlayerTool()
        {
            this.Name = "join_player";
            this.Description = "Join a new player to the game using a virtual gamepad device (only works in Play Mode during Lobby state)";
            this.IsAsync = true;
        }

        public override void ExecuteAsync(JObject parameters, TaskCompletionSource<JObject> tcs)
        {
            if (!EditorApplication.isPlaying)
            {
                tcs.SetResult(PlaytestSocketHandler.CreateErrorResponse("Cannot join player: not in Play Mode", "invalid_state"));
                return;
            }

            EditorApplication.delayCall += () =>
            {
                try
                {
                    var result = JoinNewPlayer();
                    tcs.SetResult(result);
                }
                catch (Exception ex)
                {
                    tcs.SetResult(PlaytestSocketHandler.CreateErrorResponse($"Failed to join player: {ex.Message}", "join_error"));
                }
            };
        }

        private static JObject JoinNewPlayer()
        {
            var gameManager = GameManager.instance;

            if (gameManager == null)
            {
                return PlaytestSocketHandler.CreateErrorResponse("GameManager not found", "invalid_state");
            }

            if (gameManager.currentState != GameState.Lobby)
            {
                return PlaytestSocketHandler.CreateErrorResponse("Cannot join: game is not in Lobby state", "invalid_state");
            }

            var playerInputManager = gameManager.GetComponent<PlayerInputManager>();

            if (playerInputManager == null)
            {
                return PlaytestSocketHandler.CreateErrorResponse("PlayerInputManager not found", "invalid_state");
            }

            int countBefore = PlayerInput.all.Count;

            // Create a virtual gamepad for the new player
            var virtualGamepad = InputSystem.AddDevice<Gamepad>();

            // Use PlayerInputManager.JoinPlayer with the virtual device
            PlayerInput newPlayer = PlayerInput.Instantiate(
                playerInputManager.playerPrefab,
                countBefore,
                pairWithDevice: virtualGamepad
            );

            if (newPlayer == null)
            {
                InputSystem.RemoveDevice(virtualGamepad);
                return PlaytestSocketHandler.CreateErrorResponse("Failed to instantiate player", "join_error");
            }

            int countAfter = PlayerInput.all.Count;

            return new JObject
            {
                ["success"] = true,
                ["message"] = $"Player {countBefore} joined successfully",
                ["playerIndex"] = countBefore,
                ["totalPlayers"] = countAfter
            };
        }
    }
}

