using System;
using System.Threading.Tasks;
using Newtonsoft.Json.Linq;
using UnityEditor;
using UnityEngine;
using UnityEngine.InputSystem;

namespace McpPlaytest
{
    public class SpawnPlayerTool : PlaytestToolBase
    {
        public SpawnPlayerTool()
        {
            this.Name = "spawn_player";
            this.Description = "Spawn a new player with a virtual gamepad device. Works in Play Mode when GameManager is in Lobby state. The spawned player can then be controlled via simulate_input.";
            this.IsAsync = true;
        }

        public override void ExecuteAsync(JObject parameters, TaskCompletionSource<JObject> tcs)
        {
            if (!EditorApplication.isPlaying)
            {
                tcs.SetResult(PlaytestSocketHandler.CreateErrorResponse("Cannot spawn player: not in Play Mode", "invalid_state"));
                return;
            }

            EditorApplication.delayCall += () =>
            {
                try
                {
                    var result = SpawnNewPlayer();
                    tcs.SetResult(result);
                }
                catch (Exception ex)
                {
                    tcs.SetResult(PlaytestSocketHandler.CreateErrorResponse($"Failed to spawn player: {ex.Message}", "spawn_error"));
                }
            };
        }

        private static JObject SpawnNewPlayer()
        {
            var gameManager = GameManager.instance;

            if (gameManager == null)
            {
                return PlaytestSocketHandler.CreateErrorResponse("GameManager not found", "invalid_state");
            }

            if (gameManager.currentState != GameState.Lobby)
            {
                return PlaytestSocketHandler.CreateErrorResponse("Cannot spawn: game is not in Lobby state", "invalid_state");
            }

            var playerInputManager = gameManager.GetComponent<PlayerInputManager>();

            if (playerInputManager == null)
            {
                return PlaytestSocketHandler.CreateErrorResponse("PlayerInputManager not found", "invalid_state");
            }

            int countBefore = PlayerInput.all.Count;

            // Create a virtual gamepad for the new player
            var virtualGamepad = InputSystem.AddDevice<Gamepad>();

            // Use PlayerInput.Instantiate with the virtual device
            PlayerInput newPlayer = PlayerInput.Instantiate(
                playerInputManager.playerPrefab,
                countBefore,
                pairWithDevice: virtualGamepad
            );

            if (newPlayer == null)
            {
                InputSystem.RemoveDevice(virtualGamepad);
                return PlaytestSocketHandler.CreateErrorResponse("Failed to instantiate player", "spawn_error");
            }

            int countAfter = PlayerInput.all.Count;

            return new JObject
            {
                ["success"] = true,
                ["message"] = $"Player {countBefore} spawned successfully",
                ["playerIndex"] = countBefore,
                ["totalPlayers"] = countAfter
            };
        }
    }
}

