 11â†’namespace McpPlaytest
 12â†’{
 13â†’    [InitializeOnLoad]
 14â†’    public class PlaytestServer : IDisposable
 15â†’    {
 16â†’        private static PlaytestServer _instance;
 17â†’        private readonly Dictionary<string, PlaytestToolBase> _tools = new Dictionary<string, PlaytestToolBase>();
 18â†’        private WebSocketServer _webSocketServer;
 19â†’
 20â†’        private const int DEFAULT_PORT = 8091;
 21â†’        private const string WS_PATH = "/McpPlaytest";
 22â†’        private const string SESSION_KEY_WAS_RUNNING = "McpPlaytest_WasRunning";
 23â†’
 24â†’        public ConcurrentDictionary<string, string> Clients { get; } = new ConcurrentDictionary<string, string>();
 25â†’        public bool IsListening => _webSocketServer?.IsListening ?? false;
 26â†’
 27â†’        [DidReloadScripts]
 28â†’        private static void AfterReload()
 29â†’        {
 30â†’            if (Application.isBatchMode) return;
 31â†’
 32â†’            // Always ensure instance exists after reload
 33â†’            var inst = Instance;
 34â†’
 35â†’            // If the server was running before domain reload, restart it
 36â†’            if (SessionState.GetBool(SESSION_KEY_WAS_RUNNING, false))
 37â†’            {
 38â†’                if (!inst.IsListening)
 39â†’                {
 40â†’                    inst.StartServer();
 41â†’                }
 42â†’            }
 43â†’        }
 44â†’
 45â†’        public static PlaytestServer Instance
 46â†’        {
 47â†’            get
 48â†’            {
 49â†’                if (Application.isBatchMode) return null;
 50â†’                if (_instance == null)
 51â†’                {
 52â†’                    _instance = new PlaytestServer();
 53â†’                }
 54â†’                return _instance;
 55â†’            }
 56â†’        }
