 58â†’        private PlaytestServer()
 59â†’        {
 60â†’            if (Application.isBatchMode) return;
 61â†’
 62â†’            EditorApplication.quitting -= OnEditorQuitting;
 63â†’            EditorApplication.quitting += OnEditorQuitting;
 64â†’
 65â†’            AssemblyReloadEvents.beforeAssemblyReload -= OnBeforeAssemblyReload;
 66â†’            AssemblyReloadEvents.beforeAssemblyReload += OnBeforeAssemblyReload;
 67â†’
 68â†’            EditorApplication.playModeStateChanged -= OnPlayModeStateChanged;
 69â†’            EditorApplication.playModeStateChanged += OnPlayModeStateChanged;
 70â†’
 71â†’            RegisterTools();
 72â†’            StartServer();
 73â†’        }
