 75â†’        public void Dispose()
 76â†’        {
 77â†’            StopServer();
 78â†’            EditorApplication.quitting -= OnEditorQuitting;
 79â†’            AssemblyReloadEvents.beforeAssemblyReload -= OnBeforeAssemblyReload;
 80â†’            EditorApplication.playModeStateChanged -= OnPlayModeStateChanged;
