 84â†’        public void StartServer()
 85â†’        {
 86â†’            if (IsListening)
 87â†’            {
 88â†’                Debug.Log($"[McpPlaytest] Server already listening on port {DEFAULT_PORT}");
 89â†’                return;
 90â†’            }
 91â†’
 92â†’            try
 93â†’            {
 94â†’                _webSocketServer = new WebSocketServer($"ws://localhost:{DEFAULT_PORT}");
 95â†’                _webSocketServer.ReuseAddress = true;
 96â†’                _webSocketServer.AddWebSocketService(WS_PATH, () => new PlaytestSocketHandler(this));
 97â†’                _webSocketServer.Start();
 98â†’                SessionState.SetBool(SESSION_KEY_WAS_RUNNING, true);
 99â†’                Debug.Log($"[McpPlaytest] WebSocket server started on port {DEFAULT_PORT}");
100â†’            }
101â†’            catch (SocketException ex) when (ex.SocketErrorCode == SocketError.AddressAlreadyInUse)
102â†’            {
103â†’                Debug.LogError($"[McpPlaytest] Port {DEFAULT_PORT} already in use: {ex.Message}");
104â†’            }
105â†’            catch (Exception ex)
106â†’            {
