111â†’        public void StopServer()
112â†’        {
113â†’            if (!IsListening) return;
114â†’
115â†’            try
116â†’            {
117â†’                _webSocketServer?.Stop();
118â†’                Debug.Log("[McpPlaytest] WebSocket server stopped");
119â†’            }
120â†’            catch (Exception ex)
121â†’            {
122â†’                Debug.LogError($"[McpPlaytest] Error stopping server: {ex.Message}");
123â†’            }
