136â†’        private void RegisterTools()
137â†’        {
138â†’            // Play Mode control
139â†’            var playModeControl = new PlayModeControlTool();
140â†’            _tools.Add(playModeControl.Name, playModeControl);
141â†’
142â†’            // Screenshot capture
143â†’            var captureScreenshot = new CaptureScreenshotTool();
144â†’            _tools.Add(captureScreenshot.Name, captureScreenshot);
145â†’
146â†’            // Input simulation
147â†’            var simulateInput = new SimulateInputTool();
148â†’            _tools.Add(simulateInput.Name, simulateInput);
149â†’
150â†’            // Game state query
151â†’            var queryGameState = new QueryGameStateTool();
152â†’            _tools.Add(queryGameState.Name, queryGameState);
153â†’
154â†’            // Console logs
155â†’            var getConsoleLogs = new GetConsoleLogsTool();
156â†’            _tools.Add(getConsoleLogs.Name, getConsoleLogs);
157â†’
158â†’            // Video recording
159â†’            var recordVideo = new RecordVideoTool();
160â†’            _tools.Add(recordVideo.Name, recordVideo);
161â†’
162â†’            // Player spawning
163â†’            var spawnPlayer = new SpawnPlayerTool();
164â†’            _tools.Add(spawnPlayer.Name, spawnPlayer);
165â†’        }
