167â†’        // KEY DIFFERENCE: We do NOT stop on ExitingEditMode!
168â†’        // We persist through Play Mode by saving state and restarting after domain reload
169â†’        private static void OnPlayModeStateChanged(PlayModeStateChange state)
170â†’        {
171â†’            if (Application.isBatchMode || _instance == null) return;
172â†’
173â†’            switch (state)
174â†’            {
175â†’                case PlayModeStateChange.ExitingEditMode:
176â†’                    // Save that we were running so we restart after domain reload
177â†’                    if (_instance.IsListening)
178â†’                    {
179â†’                        SessionState.SetBool(SESSION_KEY_WAS_RUNNING, true);
180â†’                    }
181â†’                    // Stop the server before domain reload destroys it
182â†’                    _instance.StopServer();
183â†’                    break;
184â†’                case PlayModeStateChange.EnteredPlayMode:
185â†’                    // After domain reload in Play Mode, restart if we were running
186â†’                    // This is handled by [DidReloadScripts] but also check here as a safety net
187â†’                    if (SessionState.GetBool(SESSION_KEY_WAS_RUNNING, false) && !_instance.IsListening)
188â†’                    {
189â†’                        _instance.StartServer();
190â†’                    }
191â†’                    break;
192â†’                case PlayModeStateChange.ExitingPlayMode:
193â†’                    // Keep running, will restart after domain reload
194â†’                    if (_instance.IsListening)
195â†’                    {
196â†’                        SessionState.SetBool(SESSION_KEY_WAS_RUNNING, true);
197â†’                    }
198â†’                    _instance.StopServer();
199â†’                    break;
200â†’                case PlayModeStateChange.EnteredEditMode:
201â†’                    // Back in edit mode, restart if we were running
202â†’                    if (SessionState.GetBool(SESSION_KEY_WAS_RUNNING, false) && !_instance.IsListening)
203â†’                    {
204â†’                        _instance.StartServer();
205â†’                    }
206â†’                    break;
207â†’            }
208â†’        }
209â†’
210â†’        private static void OnBeforeAssemblyReload()
211â†’        {
212â†’            if (Application.isBatchMode || _instance == null) return;
213â†’
214â†’            if (_instance.IsListening)
215â†’            {
216â†’                SessionState.SetBool(SESSION_KEY_WAS_RUNNING, true);
217â†’                _instance.StopServer();
218â†’            }
219â†’        }
220â†’
221â†’        private static void OnEditorQuitting()
222â†’        {
223â†’            if (Application.isBatchMode || _instance == null) return;
224â†’            SessionState.SetBool(SESSION_KEY_WAS_RUNNING, false);
225â†’            _instance.Dispose();
226â†’        }
227â†’    }
