 13â†’namespace McpPlaytest
 14â†’{
 15â†’    public class PlaytestSocketHandler : WebSocketBehavior
 16â†’    {
 17â†’        private readonly PlaytestServer _server;
 18â†’
 19â†’        public PlaytestSocketHandler(PlaytestServer server)
 20â†’        {
 21â†’            _server = server;
 22â†’        }
