 24â†’        public static JObject CreateErrorResponse(string message, string errorType)
 25â†’        {
 26â†’            return new JObject
 27â†’            {
 28â†’                ["error"] = new JObject
 29â†’                {
 30â†’                    ["type"] = errorType,
 31â†’                    ["message"] = message
 32â†’                }
 33â†’            };
 34â†’        }
 35â†’
 36â†’        protected override async void OnMessage(MessageEventArgs e)
 37â†’        {
 38â†’            try
 39â†’            {
 40â†’                JObject requestJson;
 41â†’                try
 42â†’                {
 43â†’                    requestJson = JObject.Parse(e.Data);
 44â†’                }
 45â†’                catch (JsonReaderException jre)
 46â†’                {
 47â†’                    Send(CreateResponse(null, CreateErrorResponse($"Invalid JSON: {jre.Message}", "invalid_json")).ToString(Formatting.None));
 48â†’                    return;
 49â†’                }
 50â†’
 51â†’                var method = requestJson["method"]?.ToString();
 52â†’                var parameters = requestJson["params"] as JObject ?? new JObject();
 53â†’                var requestId = requestJson["id"]?.ToString();
 54â†’
 55â†’                var tcs = new TaskCompletionSource<JObject>();
 56â†’
 57â†’                if (string.IsNullOrEmpty(method))
 58â†’                {
 59â†’                    tcs.SetResult(CreateErrorResponse("Missing method in request", "invalid_request"));
 60â†’                }
 61â†’                else if (_server.TryGetTool(method, out var tool))
 62â†’                {
 63â†’                    EditorCoroutineUtility.StartCoroutineOwnerless(ExecuteTool(tool, parameters, tcs));
 64â†’                }
 65â†’                else
 66â†’                {
 67â†’                    tcs.SetResult(CreateErrorResponse($"Unknown method: {method}", "unknown_method"));
 68â†’                }
 69â†’
 70â†’                JObject responseJson = await tcs.Task;
 71â†’                JObject jsonRpcResponse = CreateResponse(requestId, responseJson);
 72â†’                Send(jsonRpcResponse.ToString(Formatting.None));
 73â†’            }
 74â†’            catch (Exception ex)
 75â†’            {
 76â†’                Debug.LogError($"[McpPlaytest] Error processing message: {ex.Message}");
 77â†’                Send(CreateErrorResponse($"Internal error: {ex.Message}", "internal_error").ToString(Formatting.None));
 78â†’            }
 79â†’        }
 80â†’
 81â†’        protected override void OnOpen()
 82â†’        {
 83â†’            var inactiveIds = Sessions.InactiveIDs.ToList();
 84â†’            foreach (var oldId in inactiveIds)
 85â†’            {
 86â†’                _server.Clients.TryRemove(oldId, out _);
 87â†’                try
 88â†’                {
 89â†’                    Sessions.CloseSession(oldId, CloseStatusCode.Normal, "Stale session cleanup");
 90â†’                }
 91â†’                catch (Exception) { }
 92â†’            }
 93â†’
 94â†’            string clientName = "";
 95â†’            NameValueCollection headers = Context.Headers;
 96â†’            if (headers != null && headers.Contains("X-Client-Name"))
 97â†’            {
 98â†’                clientName = headers["X-Client-Name"];
 99â†’            }
100â†’
101â†’            _server.Clients[ID] = clientName;
102â†’            Debug.Log($"[McpPlaytest] Client connected (ID: {ID}, Total: {_server.Clients.Count})");
103â†’        }
104â†’
105â†’        protected override void OnClose(CloseEventArgs e)
106â†’        {
107â†’            _server.Clients.TryRemove(ID, out _);
108â†’            Debug.Log($"[McpPlaytest] Client disconnected (Remaining: {_server.Clients.Count})");
109â†’        }
110â†’
111â†’        protected override void OnError(ErrorEventArgs e)
112â†’        {
113â†’            Debug.LogError($"[McpPlaytest] WebSocket error: {e.Message}");
114â†’        }
115â†’
116â†’        private IEnumerator ExecuteTool(PlaytestToolBase tool, JObject parameters, TaskCompletionSource<JObject> tcs)
117â†’        {
118â†’            try
119â†’            {
120â†’                if (tool.IsAsync)
121â†’                {
122â†’                    tool.ExecuteAsync(parameters, tcs);
123â†’                }
124â†’                else
125â†’                {
126â†’                    var result = tool.Execute(parameters);
127â†’                    tcs.SetResult(result);
128â†’                }
129â†’            }
130â†’            catch (Exception ex)
131â†’            {
132â†’                Debug.LogError($"[McpPlaytest] Error executing tool {tool.Name}: {ex.Message}\n{ex.StackTrace}");
133â†’                tcs.SetResult(CreateErrorResponse($"Failed to execute {tool.Name}: {ex.Message}", "tool_execution_error"));
134â†’            }
135â†’
136â†’            yield return null;
137â†’        }
138â†’
139â†’        private JObject CreateResponse(string requestId, JObject result)
140â†’        {
141â†’            var response = new JObject
142â†’            {
143â†’                ["id"] = requestId
144â†’            };
145â†’
146â†’            if (result.TryGetValue("error", out var errorObj))
147â†’            {
148â†’                response["error"] = errorObj;
149â†’            }
150â†’            else
151â†’            {
152â†’                response["result"] = result;
153â†’            }
154â†’
155â†’            return response;
156â†’        }
157â†’    }
