  7â†’{
  8â†’    public static class ScreenCaptureHelper
  9â†’    {
 10â†’        public static string CaptureGameViewAsBase64(int width, int height)
 11â†’        {
 12â†’            // Try Game View RenderTexture approach first
 13â†’            string result = CaptureViaGameView(width, height);
 14â†’            if (!string.IsNullOrEmpty(result)) return result;
 15â†’
 16â†’            // Fallback to ScreenCapture
 17â†’            return CaptureViaScreenCapture(width, height);
 18â†’        }
 19â†’
 20â†’        private static string CaptureViaGameView(int width, int height)
 21â†’        {
 22â†’            try
 23â†’            {
 24â†’                // Get the Game View window via reflection
 25â†’                var gameViewType = Type.GetType("UnityEditor.GameView,UnityEditor");
 26â†’                if (gameViewType == null) return null;
 27â†’
 28â†’                var gameView = EditorWindow.GetWindow(gameViewType, false, null, false);
 29â†’                if (gameView == null) return null;
 30â†’
 31â†’                // Try to get the render texture from the game view
 32â†’                var renderTextureField = gameViewType.GetProperty("targetTexture", BindingFlags.NonPublic | BindingFlags.Instance | BindingFlags.Public);
 33â†’
 34â†’                // Alternative: use the targetDisplay approach
 35â†’                if (renderTextureField == null)
 36â†’                {
 37â†’                    // Try getting the render texture through the view's camera
 38â†’                    return CaptureViaCamera(width, height);
 39â†’                }
 40â†’
 41â†’                var renderTexture = renderTextureField.GetValue(gameView) as RenderTexture;
 42â†’                if (renderTexture == null)
 43â†’                {
 44â†’                    return CaptureViaCamera(width, height);
 45â†’                }
 46â†’
 47â†’                return ReadRenderTextureToBase64(renderTexture, width, height);
 48â†’            }
 49â†’            catch (Exception)
 50â†’            {
 51â†’                return null;
 52â†’            }
 53â†’        }
 54â†’
 55â†’        private static string CaptureViaCamera(int width, int height)
 56â†’        {
 57â†’            try
 58â†’            {
 59â†’                var mainCam = Camera.main;
 60â†’                if (mainCam == null) return null;
 61â†’
 62â†’                var rt = new RenderTexture(width, height, 24);
 63â†’                var previousTarget = mainCam.targetTexture;
 64â†’
 65â†’                mainCam.targetTexture = rt;
 66â†’                mainCam.Render();
 67â†’                mainCam.targetTexture = previousTarget;
 68â†’
 69â†’                string result = ReadRenderTextureToBase64(rt, width, height);
 70â†’
 71â†’                UnityEngine.Object.DestroyImmediate(rt);
 72â†’
 73â†’                return result;
 74â†’            }
 75â†’            catch (Exception)
 76â†’            {
 77â†’                return null;
 78â†’            }
 79â†’        }
 80â†’
 81â†’        private static string CaptureViaScreenCapture(int width, int height)
 82â†’        {
 83â†’            try
 84â†’            {
 85â†’                var texture = ScreenCapture.CaptureScreenshotAsTexture();
 86â†’                if (texture == null) return null;
 87â†’
 88â†’                // Resize if needed
 89â†’                if (texture.width != width || texture.height != height)
 90â†’                {
 91â†’                    var resized = new Texture2D(width, height, TextureFormat.RGB24, false);
 92â†’                    var rt = RenderTexture.GetTemporary(width, height);
 93â†’                    Graphics.Blit(texture, rt);
 94â†’
 95â†’                    var previousActive = RenderTexture.active;
 96â†’                    RenderTexture.active = rt;
 97â†’                    resized.ReadPixels(new Rect(0, 0, width, height), 0, 0);
 98â†’                    resized.Apply();
 99â†’                    RenderTexture.active = previousActive;
100â†’                    RenderTexture.ReleaseTemporary(rt);
101â†’
102â†’                    UnityEngine.Object.DestroyImmediate(texture);
103â†’                    texture = resized;
104â†’                }
105â†’
106â†’                byte[] pngBytes = texture.EncodeToPNG();
107â†’                UnityEngine.Object.DestroyImmediate(texture);
108â†’
109â†’                return Convert.ToBase64String(pngBytes);
110â†’            }
111â†’            catch (Exception)
112â†’            {
113â†’                return null;
114â†’            }
115â†’        }
116â†’
117â†’        private static string ReadRenderTextureToBase64(RenderTexture rt, int width, int height)
118â†’        {
119â†’            var previousActive = RenderTexture.active;
120â†’            RenderTexture.active = rt;
121â†’
122â†’            var texture = new Texture2D(rt.width, rt.height, TextureFormat.RGB24, false);
123â†’            texture.ReadPixels(new Rect(0, 0, rt.width, rt.height), 0, 0);
124â†’            texture.Apply();
125â†’
126â†’            RenderTexture.active = previousActive;
127â†’
128â†’            // Resize if needed
129â†’            if (texture.width != width || texture.height != height)
130â†’            {
131â†’                var resized = new Texture2D(width, height, TextureFormat.RGB24, false);
132â†’                var tempRt = RenderTexture.GetTemporary(width, height);
133â†’                Graphics.Blit(texture, tempRt);
134â†’
135â†’                RenderTexture.active = tempRt;
136â†’                resized.ReadPixels(new Rect(0, 0, width, height), 0, 0);
137â†’                resized.Apply();
138â†’                RenderTexture.active = previousActive;
139â†’                RenderTexture.ReleaseTemporary(tempRt);
140â†’
141â†’                UnityEngine.Object.DestroyImmediate(texture);
142â†’                texture = resized;
143â†’            }
144â†’
145â†’            byte[] pngBytes = texture.EncodeToPNG();
146â†’            UnityEngine.Object.DestroyImmediate(texture);
147â†’
148â†’            return Convert.ToBase64String(pngBytes);
149â†’        }
