 23â†’        public static JObject SimulateAction(string action, int playerIndex, JObject value, float duration)
 24â†’        {
 25â†’            var controller = FindPlayerController(playerIndex);
 26â†’            if (controller == null)
 27â†’            {
 28â†’                return PlaytestSocketHandler.CreateErrorResponse($"Player {playerIndex} not found", "player_not_found");
 29â†’            }
 30â†’
 31â†’            switch (action)
 32â†’            {
 33â†’                case "move":
 34â†’                    return SimulateMove(controller, playerIndex, value, duration);
 35â†’                case "melee_attack":
 36â†’                    return SimulateButtonPress(controller, "OnMeleeAttack");
 37â†’                case "ranged_attack":
 38â†’                    return SimulateButtonPress(controller, "OnRangedAttack");
 39â†’                case "throw_attack":
 40â†’                    return SimulateButtonPress(controller, "OnThrowAttack");
 41â†’                case "special_ability":
