198â†’                        };
199â†’                    }
200â†’                }
201â†’            }
202â†’
203â†’            // Fallback: use reflection to set the pressed bool directly
204â†’            string fieldName = callbackName switch
205â†’            {
206â†’                "OnMeleeAttack" => "meleeAttackPressed",
207â†’                "OnRangedAttack" => "rangedAttackPressed",
208â†’                "OnThrowAttack" => "throwAttackPressed",
209â†’                "OnSpecialAbility" => "specialAbilityPressed",
210â†’                _ => null
