219â†’                    var field = typeof(PlayerController).GetField($"<{fieldName}>k__BackingField",
220â†’                        System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
221â†’                    if (field != null)
222â†’                    {
223â†’                        field.SetValue(controller, true);
224â†’                        return new JObject
225â†’                        {
226â†’                            ["success"] = true,
227â†’                            ["action"] = callbackName.Replace("On", "").ToLower(),
228â†’                            ["playerIndex"] = controller.playerIndex,
229â†’                            ["method"] = "reflection"
230â†’                        };
231â†’                    }
232â†’                }
233â†’            }
