258â†’        private static void CheckSimulationExpiry()
259â†’        {
260â†’            var expired = new List<int>();
261â†’
262â†’            foreach (var kvp in _activeSimulations)
263â†’            {
264â†’                if (Time.realtimeSinceStartup >= kvp.Value.endTime)
265â†’                {
266â†’                    expired.Add(kvp.Key);
267â†’
268â†’                    // Reset the move input
269â†’                    var field = typeof(PlayerController).GetField("<moveInput>k__BackingField",
270â†’                        System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
271â†’                    if (field != null && kvp.Value.controller != null)
272â†’                    {
273â†’                        field.SetValue(kvp.Value.controller, Vector2.zero);
274â†’                    }
275â†’                }
276â†’            }
277â†’
278â†’            foreach (var key in expired)
279â†’            {
280â†’                _activeSimulations.Remove(key);
281â†’            }
282â†’
283â†’            if (_activeSimulations.Count == 0)
284â†’            {
285â†’                UnityEditor.EditorApplication.update -= CheckSimulationExpiry;
286â†’            }
287â†’        }
