  7â†’{
  8â†’    public class GetConsoleLogsTool : PlaytestToolBase
  9â†’    {
 10â†’        private static readonly List<LogEntry> _logBuffer = new List<LogEntry>();
 11â†’        private static readonly object _logLock = new object();
 12â†’        private const int MAX_LOG_ENTRIES = 500;
 13â†’        private static bool _isSubscribed = false;
 14â†’
 15â†’        private struct LogEntry
 16â†’        {
 17â†’            public string message;
 18â†’            public string stackTrace;
 19â†’            public LogType type;
 20â†’            public string timestamp;
 21â†’        }
 22â†’
 23â†’        public GetConsoleLogsTool()
 24â†’        {
 25â†’            this.Name = "get_playtest_logs";
 26â†’            this.Description = "Get recent Unity console log entries during Play Mode";
 27â†’            EnsureSubscribed();
 28â†’        }
 29â†’
 30â†’        private static void EnsureSubscribed()
 31â†’        {
 32â†’            if (_isSubscribed) return;
 33â†’            Application.logMessageReceived += OnLogMessageReceived;
 34â†’            _isSubscribed = true;
 35â†’        }
 36â†’
 37â†’        private static void OnLogMessageReceived(string condition, string stackTrace, LogType type)
 38â†’        {
 39â†’            lock (_logLock)
 40â†’            {
 41â†’                _logBuffer.Add(new LogEntry
 42â†’                {
 43â†’                    message = condition,
 44â†’                    stackTrace = stackTrace,
 45â†’                    type = type,
 46â†’                    timestamp = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss.fff")
 47â†’                });
 48â†’
 49â†’                while (_logBuffer.Count > MAX_LOG_ENTRIES)
 50â†’                {
 51â†’                    _logBuffer.RemoveAt(0);
 52â†’                }
 53â†’            }
 54â†’        }
 55â†’
 56â†’        public override JObject Execute(JObject parameters)
 57â†’        {
 58â†’            int count = parameters["count"]?.ToObject<int>() ?? 50;
 59â†’            var filter = parameters["filter"]?.ToString() ?? "all";
 60â†’
 61â†’            var logsArray = new JArray();
 62â†’
 63â†’            lock (_logLock)
 64â†’            {
 65â†’                int startIndex = Math.Max(0, _logBuffer.Count - count);
 66â†’
 67â†’                for (int i = _logBuffer.Count - 1; i >= startIndex; i--)
 68â†’                {
 69â†’                    var entry = _logBuffer[i];
 70â†’
 71â†’                    if (filter != "all")
 72â†’                    {
 73â†’                        string typeStr = this.LogTypeToFilterString(entry.type);
 74â†’                        if (typeStr != filter) continue;
 75â†’                    }
 76â†’
 77â†’                    logsArray.Add(new JObject
 78â†’                    {
 79â†’                        ["message"] = entry.message,
 80â†’                        ["stackTrace"] = entry.stackTrace,
 81â†’                        ["type"] = entry.type.ToString(),
 82â†’                        ["timestamp"] = entry.timestamp
 83â†’                    });
 84â†’
 85â†’                    if (logsArray.Count >= count) break;
 86â†’                }
 87â†’            }
 88â†’
 89â†’            return new JObject
 90â†’            {
 91â†’                ["success"] = true,
 92â†’                ["type"] = "text",
 93â†’                ["logs"] = logsArray,
 94â†’                ["totalBuffered"] = _logBuffer.Count
 95â†’            };
 96â†’        }
 97â†’
 98â†’        private string LogTypeToFilterString(LogType type)
 99â†’        {
100â†’            switch (type)
101â†’            {
102â†’                case LogType.Error:
103â†’                case LogType.Exception:
104â†’                case LogType.Assert:
105â†’                    return "error";
106â†’                case LogType.Warning:
107â†’                    return "warning";
108â†’                case LogType.Log:
109â†’                    return "log";
110â†’                default:
111â†’                    return "log";
112â†’            }
113â†’        }
114â†’    }
