  9â†’{
 10â†’    public class RecordVideoTool : PlaytestToolBase
 11â†’    {
 12â†’        private static bool _isRecording = false;
 13â†’        private static List<string> _frames = new List<string>();
 14â†’        private static float _recordStartTime;
 15â†’        private static int _targetFps = 5;
 16â†’        private static float _maxDuration = 5f;
 17â†’        private static int _captureWidth = 640;
 18â†’        private static int _captureHeight = 360;
 19â†’        private static float _lastCaptureTime;
 20â†’        private const int MAX_FRAMES = 30;
 21â†’
 22â†’        public RecordVideoTool()
 23â†’        {
 24â†’            this.Name = "record_video";
 25â†’            this.Description = "Record gameplay as a sequence of screenshot frames. Actions: start, stop, status";
 26â†’            this.IsAsync = true;
 27â†’        }
 28â†’
 29â†’        public override void ExecuteAsync(JObject parameters, TaskCompletionSource<JObject> tcs)
 30â†’        {
 31â†’            var action = parameters["action"]?.ToString();
 32â†’
 33â†’            if (string.IsNullOrEmpty(action))
 34â†’            {
 35â†’                tcs.SetResult(PlaytestSocketHandler.CreateErrorResponse("Missing 'action' parameter", "validation_error"));
 36â†’                return;
 37â†’            }
 38â†’
 39â†’            switch (action)
 40â†’            {
 41â†’                case "start":
 42â†’                    this.HandleStart(parameters, tcs);
 43â†’                    break;
 44â†’                case "stop":
 45â†’                    this.HandleStop(tcs);
 46â†’                    break;
 47â†’                case "status":
 48â†’                    this.HandleStatus(tcs);
 49â†’                    break;
 50â†’                default:
 51â†’                    tcs.SetResult(PlaytestSocketHandler.CreateErrorResponse($"Unknown action: {action}. Valid: start, stop, status", "validation_error"));
 52â†’                    break;
 53â†’            }
 54â†’        }
 55â†’
 56â†’        private void HandleStart(JObject parameters, TaskCompletionSource<JObject> tcs)
 57â†’        {
 58â†’            if (_isRecording)
 59â†’            {
 60â†’                tcs.SetResult(PlaytestSocketHandler.CreateErrorResponse("Already recording", "invalid_state"));
 61â†’                return;
 62â†’            }
 63â†’
 64â†’            if (!EditorApplication.isPlaying)
 65â†’            {
 66â†’                tcs.SetResult(PlaytestSocketHandler.CreateErrorResponse("Cannot record: not in Play Mode", "invalid_state"));
 67â†’                return;
 68â†’            }
 69â†’
 70â†’            _targetFps = parameters["fps"]?.ToObject<int>() ?? 5;
 71â†’            _maxDuration = parameters["maxDuration"]?.ToObject<float>() ?? 5f;
 72â†’            _captureWidth = parameters["width"]?.ToObject<int>() ?? 640;
 73â†’            _captureHeight = parameters["height"]?.ToObject<int>() ?? 360;
 74â†’            _frames.Clear();
 75â†’            _recordStartTime = (float)EditorApplication.timeSinceStartup;
 76â†’            _lastCaptureTime = 0f;
 77â†’            _isRecording = true;
 78â†’
 79â†’            EditorApplication.update += CaptureFrame;
 80â†’
 81â†’            tcs.SetResult(new JObject
 82â†’            {
 83â†’                ["success"] = true,
 84â†’                ["message"] = $"Recording started at {_targetFps} FPS, max {_maxDuration}s",
 85â†’                ["isRecording"] = true
 86â†’            });
 87â†’        }
 88â†’
 89â†’        private void HandleStop(TaskCompletionSource<JObject> tcs)
 90â†’        {
 91â†’            if (!_isRecording && _frames.Count == 0)
 92â†’            {
 93â†’                tcs.SetResult(PlaytestSocketHandler.CreateErrorResponse("Not currently recording and no frames captured", "invalid_state"));
 94â†’                return;
 95â†’            }
 96â†’
 97â†’            if (_isRecording)
 98â†’            {
 99â†’                EditorApplication.update -= CaptureFrame;
100â†’                _isRecording = false;
101â†’            }
102â†’
103â†’            EditorApplication.delayCall += () =>
104â†’            {
105â†’                var framesArray = new JArray();
106â†’                foreach (var frame in _frames)
107â†’                {
108â†’                    framesArray.Add(frame);
109â†’                }
110â†’
111â†’                tcs.SetResult(new JObject
112â†’                {
113â†’                    ["success"] = true,
114â†’                    ["frameCount"] = _frames.Count,
115â†’                    ["frames"] = framesArray,
116â†’                    ["format"] = "png",
117â†’                    ["width"] = _captureWidth,
118â†’                    ["height"] = _captureHeight
119â†’                });
120â†’            };
121â†’        }
122â†’
123â†’        private void HandleStatus(TaskCompletionSource<JObject> tcs)
124â†’        {
125â†’            float elapsed = _isRecording ? (float)EditorApplication.timeSinceStartup - _recordStartTime : _maxDuration;
126â†’
127â†’            tcs.SetResult(new JObject
128â†’            {
129â†’                ["success"] = true,
130â†’                ["isRecording"] = _isRecording,
131â†’                ["frameCount"] = _frames.Count,
132â†’                ["elapsedTime"] = elapsed,
133â†’                ["hasFrames"] = _frames.Count > 0
134â†’            });
135â†’        }
136â†’
137â†’        private static void CaptureFrame()
138â†’        {
139â†’            if (!_isRecording) return;
140â†’
141â†’            float elapsed = (float)EditorApplication.timeSinceStartup - _recordStartTime;
142â†’
143â†’            if (elapsed >= _maxDuration || _frames.Count >= MAX_FRAMES)
144â†’            {
145â†’                EditorApplication.update -= CaptureFrame;
146â†’                _isRecording = false;
147â†’                return;
148â†’            }
149â†’
150â†’            float interval = 1f / _targetFps;
151â†’            if (EditorApplication.timeSinceStartup - _lastCaptureTime < interval) return;
152â†’
153â†’            _lastCaptureTime = (float)EditorApplication.timeSinceStartup;
154â†’
155â†’            try
156â†’            {
157â†’                string base64 = ScreenCaptureHelper.CaptureGameViewAsBase64(_captureWidth, _captureHeight);
158â†’                if (!string.IsNullOrEmpty(base64))
159â†’                {
160â†’                    _frames.Add(base64);
161â†’                }
162â†’            }
163â†’            catch (Exception ex)
164â†’            {
165â†’                Debug.LogWarning($"[McpPlaytest] Frame capture failed: {ex.Message}");
166â†’            }
167â†’        }
168â†’    }
169â†’}
