  5â†’
  6â†’interface PendingRequest {
  7â†’  resolve: (value: any) => void;
  8â†’  reject: (reason: any) => void;
  9â†’  timeout: NodeJS.Timeout;
 10â†’}
 11â†’
 12â†’interface UnityRequest {
 13â†’  id?: string;
 14â†’  method: string;
 15â†’  params: any;
 16â†’}
 17â†’
 18â†’interface UnityResponse {
 19â†’  id: string;
 20â†’  result?: any;
 21â†’  error?: {
 22â†’    message: string;
 23â†’    type: string;
 24â†’  };
 25â†’}
 26â†’
 27â†’export class PlaytestUnity {
 28â†’  private logger: Logger;
 29â†’  private port: number = 8091;
 30â†’  private host: string = 'localhost';
 31â†’  private wsPath: string = '/McpPlaytest';
 32â†’  private requestTimeout: number = 30000; // 30s default â€” longer for Play Mode operations
 33â†’  private ws: WebSocket | null = null;
 34â†’  private pendingRequests: Map<string, PendingRequest> = new Map();
 35â†’  private reconnectTimer: NodeJS.Timeout | null = null;
 36â†’  private isConnected: boolean = false;
 37â†’  private clientName: string = '';
 38â†’  private maxReconnectAttempts: number = 50;
 39â†’  private reconnectAttempt: number = 0;
 40â†’  private baseReconnectDelay: number = 1000;
 41â†’  private maxReconnectDelay: number = 10000;
 42â†’
 43â†’  constructor(logger: Logger) {
 44â†’    this.logger = logger;
 45â†’  }
 46â†’
 47â†’  public async start(clientName?: string): Promise<void> {
 48â†’    this.clientName = clientName || '';
 49â†’
 50â†’    // Try reading port from config
 51â†’    try {
 52â†’      const fs = await import('fs');
 53â†’      const path = await import('path');
 54â†’      const settingsPath = path.resolve(process.cwd(), './ProjectSettings/McpPlaytestSettings.json');
 55â†’      const content = fs.readFileSync(settingsPath, 'utf-8');
 56â†’      const config = JSON.parse(content);
 57â†’      if (config.Port) this.port = config.Port;
 58â†’      if (config.Host) this.host = config.Host;
 59â†’      if (config.RequestTimeoutSeconds) this.requestTimeout = config.RequestTimeoutSeconds * 1000;
 60â†’    } catch {
 61â†’      this.logger.debug('No McpPlaytestSettings.json found, using defaults');
 62â†’    }
 63â†’
 64â†’    this.logger.info(`Connecting to Unity PlaytestServer at ws://${this.host}:${this.port}${this.wsPath}`);
 65â†’
 66â†’    try {
 67â†’      await this.connect();
 68â†’    } catch (error) {
 69â†’      this.logger.warn(`Initial connection failed: ${error instanceof Error ? error.message : String(error)}`);
 70â†’      this.logger.warn('Will retry on next request');
 71â†’    }
 72â†’  }
 73â†’
 74â†’  private connect(): Promise<void> {
 75â†’    return new Promise((resolve, reject) => {
 76â†’      const url = `ws://${this.host}:${this.port}${this.wsPath}`;
 77â†’      const headers: Record<string, string> = {};
 78â†’      if (this.clientName) {
 79â†’        headers['X-Client-Name'] = this.clientName;
 80â†’      }
 81â†’
 82â†’      this.ws = new WebSocket(url, { headers });
 83â†’
 84â†’      const connectTimeout = setTimeout(() => {
 85â†’        if (this.ws && this.ws.readyState === WebSocket.CONNECTING) {
 86â†’          this.ws.terminate();
 87â†’          reject(new McpPlaytestError(ErrorType.CONNECTION, 'Connection timeout'));
 88â†’        }
 89â†’      }, 5000);
 90â†’
 91â†’      this.ws.on('open', () => {
 92â†’        clearTimeout(connectTimeout);
 93â†’        this.isConnected = true;
 94â†’        this.reconnectAttempt = 0;
 95â†’        this.logger.info('Connected to Unity PlaytestServer');
 96â†’        resolve();
 97â†’      });
 98â†’
 99â†’      this.ws.on('message', (data: WebSocket.Data) => {
100â†’        this.handleMessage(data.toString());
101â†’      });
102â†’
103â†’      this.ws.on('close', (code: number, reason: Buffer) => {
104â†’        clearTimeout(connectTimeout);
105â†’        this.isConnected = false;
106â†’        this.logger.info(`WebSocket closed: ${code} ${reason.toString()}`);
107â†’        this.scheduleReconnect();
108â†’      });
109â†’
110â†’      this.ws.on('error', (error: Error) => {
111â†’        clearTimeout(connectTimeout);
112â†’        this.isConnected = false;
113â†’        this.logger.error(`WebSocket error: ${error.message}`);
114â†’        if (!this.isConnected) {
115â†’          reject(new McpPlaytestError(ErrorType.CONNECTION, error.message));
116â†’        }
117â†’      });
118â†’    });
119â†’  }
120â†’
121â†’  private handleMessage(data: string): void {
122â†’    try {
123â†’      const response = JSON.parse(data) as UnityResponse;
124â†’
125â†’      if (response.id && this.pendingRequests.has(response.id)) {
126â†’        const request = this.pendingRequests.get(response.id)!;
127â†’        clearTimeout(request.timeout);
128â†’        this.pendingRequests.delete(response.id);
129â†’
130â†’        if (response.error) {
131â†’          request.reject(new McpPlaytestError(
132â†’            ErrorType.TOOL_EXECUTION,
133â†’            response.error.message || 'Unknown error'
134â†’          ));
135â†’        } else {
136â†’          request.resolve(response.result);
137â†’        }
138â†’      }
139â†’    } catch (e) {
140â†’      this.logger.error(`Error parsing message: ${e instanceof Error ? e.message : String(e)}`);
141â†’    }
142â†’  }
143â†’
144â†’  private scheduleReconnect(): void {
145â†’    if (this.reconnectTimer) return;
146â†’    if (this.reconnectAttempt >= this.maxReconnectAttempts) {
147â†’      this.logger.error('Max reconnection attempts reached');
148â†’      this.rejectAllPending(new McpPlaytestError(ErrorType.CONNECTION, 'Max reconnection attempts reached'));
149â†’      return;
150â†’    }
151â†’
152â†’    const delay = Math.min(
153â†’      this.baseReconnectDelay * Math.pow(1.5, this.reconnectAttempt),
154â†’      this.maxReconnectDelay
155â†’    );
156â†’    // Add jitter
157â†’    const jitter = delay * (0.8 + Math.random() * 0.4);
158â†’
159â†’    this.reconnectAttempt++;
160â†’    this.logger.info(`Reconnecting in ${Math.round(jitter)}ms (attempt ${this.reconnectAttempt}/${this.maxReconnectAttempts})`);
161â†’
162â†’    this.reconnectTimer = setTimeout(async () => {
163â†’      this.reconnectTimer = null;
164â†’      try {
165â†’        await this.connect();
166â†’      } catch {
167â†’        // Will schedule another reconnect via the close handler
168â†’      }
169â†’    }, jitter);
170â†’  }
171â†’
172â†’  private rejectAllPending(error: McpPlaytestError): void {
173â†’    for (const [id, request] of this.pendingRequests.entries()) {
174â†’      clearTimeout(request.timeout);
175â†’      request.reject(error);
176â†’      this.pendingRequests.delete(id);
177â†’    }
178â†’  }
179â†’
180â†’  public async sendRequest(request: UnityRequest): Promise<any> {
181â†’    const requestId = request.id || uuidv4();
182â†’    const message: UnityRequest = { ...request, id: requestId };
183â†’
184â†’    // If not connected, try to connect
185â†’    if (!this.isConnected || !this.ws || this.ws.readyState !== WebSocket.OPEN) {
186â†’      this.logger.info('Not connected, attempting to connect...');
187â†’      try {
188â†’        await this.connect();
189â†’      } catch (error) {
190â†’        throw new McpPlaytestError(
191â†’          ErrorType.CONNECTION,
192â†’          `Not connected to Unity: ${error instanceof Error ? error.message : String(error)}`
193â†’        );
194â†’      }
195â†’    }
196â†’
197â†’    return new Promise((resolve, reject) => {
198â†’      const timeout = setTimeout(() => {
199â†’        if (this.pendingRequests.has(requestId)) {
200â†’          this.pendingRequests.delete(requestId);
201â†’          reject(new McpPlaytestError(ErrorType.TIMEOUT, `Request timed out after ${this.requestTimeout}ms`));
202â†’        }
203â†’      }, this.requestTimeout);
204â†’
205â†’      this.pendingRequests.set(requestId, { resolve, reject, timeout });
206â†’
207â†’      try {
208â†’        this.ws!.send(JSON.stringify(message));
209â†’        this.logger.debug(`Request sent: ${requestId} (${request.method})`);
210â†’      } catch (err) {
211â†’        clearTimeout(timeout);
212â†’        this.pendingRequests.delete(requestId);
213â†’        reject(new McpPlaytestError(ErrorType.CONNECTION, `Send failed: ${err instanceof Error ? err.message : String(err)}`));
214â†’      }
215â†’    });
216â†’  }
217â†’
218â†’  public async stop(): Promise<void> {
219â†’    if (this.reconnectTimer) {
220â†’      clearTimeout(this.reconnectTimer);
221â†’      this.reconnectTimer = null;
222â†’    }
223â†’    this.rejectAllPending(new McpPlaytestError(ErrorType.CONNECTION, 'Server stopping'));
224â†’    if (this.ws) {
225â†’      this.ws.close();
226â†’      this.ws = null;
227â†’    }
228â†’    this.isConnected = false;
229â†’    this.logger.info('PlaytestUnity client stopped');
230â†’  }
231â†’}
