 12â†’
 13â†’// Initialize loggers
 14â†’const serverLogger = new Logger('Server', LogLevel.INFO);
 15â†’const unityLogger = new Logger('Unity', LogLevel.INFO);
 16â†’const toolLogger = new Logger('Tools', LogLevel.INFO);
 17â†’
 18â†’// Initialize the MCP server
 19â†’const server = new McpServer(
 20â†’  {
 21â†’    name: "MCP Playtest Server",
 22â†’    version: "1.0.0"
 23â†’  },
 24â†’  {
 25â†’    capabilities: {
 26â†’      tools: {}
 27â†’    }
 28â†’  }
 29â†’);
 30â†’
 31â†’// Initialize the Unity bridge
 32â†’const playtestUnity = new PlaytestUnity(unityLogger);
