 43â†’// Server startup
 44â†’async function startServer() {
 45â†’  try {
 46â†’    const stdioTransport = new StdioServerTransport();
 47â†’    await server.connect(stdioTransport);
 48â†’    serverLogger.info('MCP Playtest Server started');
 49â†’
 50â†’    const clientName = server.server.getClientVersion()?.name || 'Unknown MCP Client';
 51â†’    serverLogger.info(`Connected MCP client: ${clientName}`);
 52â†’
 53â†’    await playtestUnity.start(clientName);
 54â†’  } catch (error) {
 55â†’    serverLogger.error('Failed to start server', error);
 56â†’    process.exit(1);
 57â†’  }
 58â†’}
 59â†’
 60â†’// Graceful shutdown
 61â†’let isShuttingDown = false;
 62â†’async function shutdown() {
 63â†’  if (isShuttingDown) return;
 64â†’  isShuttingDown = true;
 65â†’
 66â†’  try {
 67â†’    serverLogger.info('Shutting down...');
 68â†’    await playtestUnity.stop();
 69â†’    await server.close();
 70â†’  } catch (error) {
 71â†’    // Ignore errors during shutdown
 72â†’  }
 73â†’  process.exit(0);
 74â†’}
 75â†’
 76â†’// Start
 77â†’startServer();
 78â†’
 79â†’// Handle shutdown signals
 80â†’process.on('SIGINT', shutdown);
 81â†’process.on('SIGTERM', shutdown);
 82â†’process.on('SIGHUP', shutdown);
 83â†’process.stdin.on('close', shutdown);
 84â†’process.stdin.on('end', shutdown);
 85â†’process.stdin.on('error', shutdown);
 86â†’
 87â†’process.on('uncaughtException', (error: NodeJS.ErrnoException) => {
