 1â†’import { appendFileSync } from 'fs';
 2â†’
 3â†’export enum LogLevel {
 4â†’  DEBUG = 0,
 5â†’  INFO = 1,
 6â†’  WARN = 2,
 7â†’  ERROR = 3
 8â†’}
 9â†’
10â†’const isLoggingEnabled = process.env.LOGGING === 'true';
11â†’const isLoggingFileEnabled = process.env.LOGGING_FILE === 'true';
12â†’
13â†’export class Logger {
14â†’  private level: LogLevel;
15â†’  private prefix: string;
16â†’
17â†’  constructor(prefix: string, level: LogLevel = LogLevel.INFO) {
18â†’    this.prefix = prefix;
19â†’    this.level = level;
20â†’  }
21â†’
22â†’  debug(message: string, data?: any) {
23â†’    this.log(LogLevel.DEBUG, message, data);
24â†’  }
25â†’
26â†’  info(message: string, data?: any) {
27â†’    this.log(LogLevel.INFO, message, data);
28â†’  }
29â†’
30â†’  warn(message: string, data?: any) {
31â†’    this.log(LogLevel.WARN, message, data);
32â†’  }
33â†’
34â†’  error(message: string, error?: any) {
35â†’    this.log(LogLevel.ERROR, message, error);
36â†’  }
37â†’
38â†’  private log(level: LogLevel, message: string, data?: any) {
39â†’    if (level < this.level) return;
40â†’
41â†’    const timestamp = new Date().toISOString();
42â†’    const levelStr = LogLevel[level];
43â†’    const logMessage = `[${timestamp}] [${levelStr}] [${this.prefix}] ${message}`;
44â†’
45â†’    if (isLoggingFileEnabled) {
46â†’      try {
47â†’        appendFileSync('mcp-playtest.log', logMessage + '\n');
48â†’        if (data) {
49â†’          appendFileSync('mcp-playtest.log', JSON.stringify(data, null, 2) + '\n');
50â†’        }
51â†’      } catch (error) {
52â†’        // Ignore file write errors
53â†’      }
54â†’    }
55â†’
56â†’    if (isLoggingEnabled) {
57â†’      if (data) {
58â†’        console.error(logMessage, data);
59â†’      } else {
60â†’        console.error(logMessage);
61â†’      }
62â†’    }
63â†’  }
64â†’}
