  8â†’
  9â†’namespace McpPlaytest
 10â†’{
 11â†’    public static class InputSimulator
 12â†’    {
 13â†’        private static readonly Dictionary<int, InputSimulationState> _activeSimulations = new Dictionary<int, InputSimulationState>();
 14â†’
 15â†’        private class InputSimulationState
 16â†’        {
 17â†’            public Gamepad gamepad;
 18â†’            public string action;
 19â†’            public float endTime;
 20â†’            public Vector2 moveValue;
 21â†’        }
 22â†’
 23â†’        public static JObject SimulateAction(string action, int playerIndex, JObject value, float duration)
 24â†’        {
 25â†’            switch (action)
 26â†’            {
 27â†’                case "move":
 28â†’                    return SimulateMove(playerIndex, value, duration);
 29â†’                case "melee_attack":
 30â†’                case "ranged_attack":
 31â†’                case "throw_attack":
 32â†’                case "special_ability":
 33â†’                    return SimulateButton(playerIndex, action);
 34â†’                case "stop":
 35â†’                    return SimulateMove(playerIndex, null, 0f);
 36â†’                default:
 37â†’                    return PlaytestSocketHandler.CreateErrorResponse($"Unknown action: {action}. Valid: move, melee_attack, ranged_attack, throw_attack, special_ability, stop", "validation_error");
 38â†’            }
 39â†’        }
 40â†’
 41â†’        private static JObject SimulateMove(int playerIndex, JObject value, float duration)
 42â†’        {
 43â†’            float x = value?["x"]?.ToObject<float>() ?? 0f;
 44â†’            float y = value?["y"]?.ToObject<float>() ?? 0f;
 45â†’
 46â†’            var playerInput = FindPlayerInput(playerIndex);
 47â†’            if (playerInput == null)
 48â†’            {
 49â†’                return PlaytestSocketHandler.CreateErrorResponse($"Player {playerIndex} not found", "player_not_found");
 50â†’            }
 51â†’
 52â†’            // Try to find a gamepad among paired devices
 53â†’            Gamepad gamepad = FindGamepad(playerInput);
 54â†’
 55â†’            if (gamepad != null)
 56â†’            {
 57â†’                InputState.Change(gamepad.leftStick, new Vector2(x, y));
 58â†’
 59â†’                if (duration > 0f)
 60â†’                {
 61â†’                    ScheduleMoveReset(gamepad, playerIndex, duration);
 62â†’                }
 63â†’
 64â†’                return new JObject
 65â†’                {
 66â†’                    ["success"] = true,
 67â†’                    ["action"] = "move",
 68â†’                    ["playerIndex"] = playerIndex,
 69â†’                    ["appliedValue"] = new JObject { ["x"] = x, ["y"] = y },
 70â†’                    ["duration"] = duration,
 71â†’                    ["method"] = "gamepad_stick"
 72â†’                };
 73â†’            }
 74â†’
 75â†’            // No gamepad found - try to find any device with a stick/vector2 control for Move action
 76â†’            var moveAction = playerInput.actions?.FindAction("Move");
 77â†’            if (moveAction != null)
 78â†’            {
 79â†’                foreach (var control in moveAction.controls)
 80â†’                {
 81â†’                    if (control is Vector2Control vec2)
 82â†’                    {
 83â†’                        InputState.Change(vec2, new Vector2(x, y));
 84â†’
 85â†’                        return new JObject
 86â†’                        {
 87â†’                            ["success"] = true,
 88â†’                            ["action"] = "move",
 89â†’                            ["playerIndex"] = playerIndex,
 90â†’                            ["appliedValue"] = new JObject { ["x"] = x, ["y"] = y },
 91â†’                            ["duration"] = duration,
 92â†’                            ["method"] = "action_control"
 93â†’                        };
 94â†’                    }
 95â†’                }
 96â†’            }
 97â†’
 98â†’            return PlaytestSocketHandler.CreateErrorResponse("Could not inject movement input: no suitable device or control found", "input_error");
 99â†’        }
100â†’
101â†’        private static JObject SimulateButton(int playerIndex, string action)
102â†’        {
103â†’            // Try the bridge interface first for game-specific button handling
104â†’            var bridge = FindInputReceiverBridge();
105â†’            if (bridge != null)
106â†’            {
107â†’                var bridgeResult = bridge.SimulateButtonPress(playerIndex, action);
108â†’                if (bridgeResult != null && bridgeResult["success"]?.ToObject<bool>() == true)
109â†’                {
110â†’                    return bridgeResult;
111â†’                }
112â†’            }
113â†’
114â†’            // Fall back to generic gamepad button simulation
115â†’            var playerInput = FindPlayerInput(playerIndex);
116â†’            if (playerInput == null)
117â†’            {
118â†’                return PlaytestSocketHandler.CreateErrorResponse($"Player {playerIndex} not found", "player_not_found");
119â†’            }
120â†’
121â†’            Gamepad gamepad = FindGamepad(playerInput);
122â†’            if (gamepad != null)
123â†’            {
124â†’                InputControl button = MapActionToGamepadButton(gamepad, action);
125â†’
126â†’                if (button is ButtonControl btn)
127â†’                {
128â†’                    InputState.Change(btn, 1f);
129â†’
130â†’                    UnityEditor.EditorApplication.delayCall += () =>
131â†’                    {
132â†’                        InputState.Change(btn, 0f);
133â†’                    };
134â†’
135â†’                    return new JObject
136â†’                    {
137â†’                        ["success"] = true,
138â†’                        ["action"] = action,
139â†’                        ["playerIndex"] = playerIndex,
140â†’                        ["method"] = "gamepad_button"
141â†’                    };
142â†’                }
143â†’            }
144â†’
145â†’            // Last resort: try to trigger the action directly via its bound controls
146â†’            var inputAction = FindInputAction(playerInput, action);
147â†’            if (inputAction != null)
148â†’            {
149â†’                foreach (var control in inputAction.controls)
150â†’                {
151â†’                    if (control is ButtonControl actionBtn)
152â†’                    {
153â†’                        InputState.Change(actionBtn, 1f);
154â†’
155â†’                        UnityEditor.EditorApplication.delayCall += () =>
156â†’                        {
157â†’                            InputState.Change(actionBtn, 0f);
158â†’                        };
159â†’
160â†’                        return new JObject
161â†’                        {
162â†’                            ["success"] = true,
163â†’                            ["action"] = action,
164â†’                            ["playerIndex"] = playerIndex,
165â†’                            ["method"] = "action_control"
166â†’                        };
167â†’                    }
168â†’                }
169â†’            }
170â†’
171â†’            return PlaytestSocketHandler.CreateErrorResponse($"Could not simulate {action}: no suitable device, control, or IPlaytestInputReceiver found", "input_error");
172â†’        }
173â†’
174â†’        private static InputAction FindInputAction(PlayerInput playerInput, string action)
175â†’        {
176â†’            if (playerInput.actions == null) return null;
177â†’
178â†’            // Try common naming conventions for the action
179â†’            // Capitalize first letter of each segment
180â†’            string[] parts = action.Split('_');
181â†’            for (int i = 0; i < parts.Length; i++)
182â†’            {
183â†’                if (parts[i].Length > 0)
184â†’                {
185â†’                    parts[i] = char.ToUpper(parts[i][0]) + parts[i].Substring(1);
186â†’                }
187â†’            }
188â†’            string joined = string.Join("", parts);
189â†’
190â†’            var found = playerInput.actions.FindAction(joined);
191â†’            if (found != null) return found;
192â†’
193â†’            found = playerInput.actions.FindAction(action);
194â†’            if (found != null) return found;
195â†’
196â†’            return null;
197â†’        }
