199â†’        private static InputControl MapActionToGamepadButton(Gamepad gamepad, string action)
200â†’        {
201â†’            switch (action)
202â†’            {
203â†’                case "melee_attack": return gamepad.buttonEast;
204â†’                case "ranged_attack": return gamepad.buttonSouth;
205â†’                case "throw_attack": return gamepad.buttonWest;
206â†’                case "special_ability": return gamepad.buttonNorth;
207â†’                default: return null;
208â†’            }
209â†’        }
