            // Fallback: find all PlayerControllers in scene
            var controllers = Object.FindObjectsByType<PlayerController>(FindObjectsSortMode.None);
            foreach (var ctrl in controllers)
            {
                if (ctrl.playerIndex == playerIndex)
                {
                    return ctrl;
                }
            }

            return null;
        }
