        }

        public override JObject Execute(JObject parameters)
        {
            var query = parameters["query"]?.ToString() ?? "full";

            var bridge = FindGameStateBridge();
            if (bridge == null)
            {
                return new JObject
                {
                    ["success"] = false,
                    ["error"] = "No IPlaytestGameState implementation found in scene. Add a MonoBehaviour implementing McpPlaytest.IPlaytestGameState to enable game state queries.",
                    ["isPlayMode"] = UnityEditor.EditorApplication.isPlaying
                };
            }

            switch (query)
